        GO_FORTH_AND_FROLIC_IN_YOUR_NEW_ABODE                                   = 6940,  -- Go forth and frolic in your new abode, kupo!
        YOU_CAN_ACCESS_THE_ANTECHAMBERS_FROM_THE_FRONT                          = 6941,  -- You can access the antechambers from the front door. Enjoy!
        MIGHT_BRING_A_CERTAIN_JE_NE_SAIS_QUOI                                   = 6942,  -- % might bring a certain je ne sais quoi to your Mog House, kupo!
        AH_I_NEVER_THOUGHT_THAT_THIS_DAY_WOULD                                  = 6943,  -- Ah, I never thought that this day would come, kupo...
        INDEED_IT_SEEMS_LIKE_JUST_YESTERDAY_THAT_WE                             = 6944,  -- Indeed, it seems like just yesterday that we first met here.
        I_HAVE_WATCHED_WITH_WONDER_AS_YOU_GREW                                  = 6945,  -- I have watched with wonder as you grew before my very eyes, kupo.
        IN_FACT_I_HEARD_MANY_TALES_OF_YOUR                                      = 6946,  -- In fact, I heard many tales of your boundless bravery from my friends across the world.
        EVERY_TIME_IT_MADE_ME_FEEL_MUCH_LIKE                                    = 6947,  -- Every time, it made me feel much like a proud parent would.
        IT_WAS_LIKE_I_WAS_RIGHT_THERE_WITH                                      = 6948,  -- It was like I was right there with you, kupo.
        THAT_IS_WHY_I_CEASELESSLY_CLEANED_YOUR_MOG                              = 6949,  -- That is why I ceaselessly cleaned your Mog House, merrily managed your belongings, and watered your plants.
        I_COULDN_T_REALLY_THINK_OF_ANY_OTHER                                    = 6950,  -- I couldn't really think of any other ways to help you, kupo.
        HOWEVER_I_HEARD_ABOUT_THE_TRIALS_AND_TRIBULATIONS                       = 6951,  -- However, I heard about the trials and tribulations that you've been through.
        VALHALLA_THE_MAELSTROM_MAGE_CHAOS                                       = 6952,  -- Valhalla, the Maelstrom Mage, Chaos...
        KUPOPOPO_NOW_I_CAN_ACTUALLY_ASSIST_YOU                                  = 6953,  -- Kupopopo! Now I can actually assist you!
        IT_IS_TIME_FOR_US_TO_JOYFULLY_JOIN                                      = 6954,  -- It is time for us to joyfully join forces, kupo!
