        YOU_NEED_GIL_TO_PURCHASE_A_YOU_DO                                       = 6959,  -- You need # gil to purchase a [World Pass/Gold World Pass]. You do not have enough gil to obtain one.
        YOU_NEED_GIL_TO_OBTAIN_A                                                = 6960,  -- You need # gil to obtain a [World Pass/Gold World Pass].
        WE_CAN_ISSUE_YOU_A_GOLD_WORLD_PASS                                      = 6961,  -- We can issue you a Gold World Pass, which bestows special benefits and can be used to invite friends to play in the same world as you are in now. How may we help you today?
        HOW_MAY_WE_HELP_YOU_I_M_FINE                                            = 6962,  -- How may we help you? I'm fine right now, thanks. Purchase a World Pass. Purchase a Gold World Pass. Tell me about Gold World Passes. Gold World Pass benefits.
        YOUR_WORLD_PASS_IS_NUMBER_OF_USES_LEFT                                  = 6963,  -- Your World Pass is: % Number of uses left: # Pass becomes invalid in: # [hour/hours] (Earth time)
        PURCHASE_A_YES_NO                                                       = 6964,  -- Purchase a [World Pass/Gold World Pass]? Yes. No.
        WHEN_USING_A_GOLD_WORLD_PASS_TO_INVITE                                  = 6965,  -- When using a Gold World Pass to invite a friend to this world, both you and your friend will be eligible for special benefits.
        A_GOLD_WORLD_PASS_CANNOT_BE_USED_IF                                     = 6966,  -- A Gold World Pass cannot be used if your account has more than one character.
        A_GOLD_WORLD_PASS_CAN_BE_USED_TO                                        = 6967,  -- A Gold World Pass can be used to invite one person per pass. As with the standard World Pass, a new pass cannot be issued until the current pass expires.
        BOTH_THE_INVITER_AND_THE_INVITEE_WILL_BE                                = 6968,  -- Both the inviter and the invitee will be eligible to receive special items; the invitee five times (once immediately following the generation of a character using the Gold World Pass, followed by 40 days, 70 days, 100 days, and 365 days subsequent to that date) and the inviter four times (the same occasions as the invitee, excluding the time of initial character generation).
        SPECIAL_ITEMS_CAN_BE_RECEIVED_BY_FORMING_A                              = 6969,  -- Special items can be received by forming a two-person party that includes the inviting and invited character, then choosing the option Gold World Pass benefits.
        IT_IS_POSSIBLE_TO_PUT_SPECIAL_ITEMS_ON                                  = 6970,  -- It is possible to put special items on hold to be received at a later date. However, please be aware that the following sequence of actions will render you unable to receive your gift.
        ID_1_THE_INVITEE_ACCEPTS_THE_ITEM_BUT_YOU                               = 6971,  -- (1) The invitee accepts the item, but you do not. (2) You claim an item for the same anniversary, but with a different invitee.
        THERE_IS_NO_LIMIT_TO_THE_NUMBER_OF                                      = 6972,  -- There is no limit to the number of Gold World Passes that can be issued to a person, but please be aware that a character can only receive special items from up to fifteen invites.
        PLEASE_CHOOSE_THIS_OPTION_AFTER_FORMING_A_TWO                           = 6973,  -- Please choose this option after forming a two-person party that includes the inviting and invited character.
        PLEASE_RETURN_FOR_YOUR_SPECIAL_ITEMS_IN_EARTH                           = 6974,  -- Please return for your special items in # [day/days] (Earth time).
        YOU_HAVE_ALREADY_ACCOMPANIED_TO_RECEIVE_YOUR_DAY                        = 6975,  -- You have already accompanied # [person/people] to receive your [1st/40th/70th/100th/365th]-day special item.
        YOU_HAVE_ALREADY_ACCOMPANIED_THIS_PERSON_TO_RECEIVE                     = 6976,  -- You have already accompanied this person to receive your [1st/40th/70th/100th/365th]-day special item.
        YOUR_FRIEND_HAS_NOT_YET_RECEIVED_A_SPECIAL                              = 6977,  -- Your friend has not yet received a special item. Please wait for your friend to receive an item first.
        IT_IS_TIME_TO_RECEIVE_YOUR_DAY_SPECIAL                                  = 6978,  -- It is time to receive your [1st/40th/70th/100th/365th]-day special item.
        YOU_ARE_ELIGIBLE_TO_SELECT_A_DAY_SPECIAL                                = 6979,  -- You are eligible to select a [1st/40th/70th/100th/365th]-day special item. Please choose from the list below.
        IF_YOU_CHOOSE_TO_RECEIVE_YOUR_ITEM_PLEASE                               = 6980,  -- If you choose to receive your item, please check whether or not your friend has done the same.
        PLEASE_BE_SURE_TO_COLLECT_YOUR_ITEM_BEFORE                              = 6981,  -- Please be sure to collect your item before claiming another with a different person for the same anniversary. Failure to do so will cause the unclaimed item to be lost forever.
        WHICH_ITEM_DO_YOU_CHOOSE_LET_ME_THINK                                   = 6982,  -- Which item do you choose? Let me think about it. %. %. %. %. %. %. %. Special item list I. Special item list II.
        WHICH_ITEM_DO_YOU_CHOOSE_LET_ME_THINK_2                                 = 6983,  -- Which item do you choose? Let me think about it. % (set of 12). %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. Choose a different item.
        YOUR_PARTY_MAKEUP_HAS_CHANGED_SO_YOU_WERE                               = 6984,  -- Your party makeup has changed so you were unable to receive the item. Please try again.
        HERE_IS_YOUR_SPECIAL_ITEM                                               = 6985,  -- Here is your special item.
        ACCEPT_THE_ITEM_YES_NO                                                  = 6986,  -- Accept the item? Yes. No.
        HEY_THERRRE_MISTER_MISS_HAVE_YOU_HEARD_HAVE                             = 6987,  -- Hey therrre, mister/miss]! Have you heard? Have you?
        WELL_HAVE_YOU_WHAT_ARE_YOU_TALKING_ABOUT                                = 6988,  -- Well, have you? What are you talking about? Yes, I have!
        REOOOW_WELL_I_GUESS_I_DON_T_HAVE                                        = 6989,  -- Reooow. Well, I guess I don't have to tell you, then.
        DO_YOU_RRREALLY_WANNA_KNOW_REALLY_REALLY_LISTEN                         = 6990,  -- Do you rrreally wanna know? Really? Really? Listen! I know the secrets of gar-den-ing.
        WHAT_DO_YOU_WANNA_KNOW_WHAT_DO_YOU                                      = 6991,  -- What do you wanna know? What do you wanna know?
        WHAT_DO_YOU_WANT_TO_KNOW_WHAT_IS                                        = 6992,  -- What do you want to know? What is gardening? What do I need to start? How do I garden? Are there any limits? Bye-bye!
        MEOWWW                                                                  = 6993,  -- Meowww...
        TAKE_A_SEED_PLANT_IT_IN_A_FLOWERPOT                                     = 6994,  -- Take a seed, plant it in a flowerpot, and leave the rest to your moogle! That's garrrdening!
        THEN_AFTER_A_WHILE_A_PRRRETTY_FLOWER_BLOOMS                             = 6995,  -- Then, after a while, a prrretty flower blooms!
        AND_THEN_AND_THEN_THE_FLOWER_TURRRNS_INTO                               = 6996,  -- And then, and then the flower turrrns into fruit, and you can get all kinds of neat stuff!
        STARES_OFF_INTO_THE_DISTANCE                                            = 6997,  -- stares off into the distance.
        OOPS_I_WAS_JUST_THINKING_ABOUT_ALL_THAT                                 = 6998,  -- Oops! I was just thinking about all that delicious fruit. Purrrrrr...
        UM_OKAY_TO_START_OFF_YOU_RE_GONNA                                       = 6999,  -- Um, okay, to start off, you're gonna need a flowerrrpot and some seeds.
        YOU_CAN_BUY_FLOWERRRPOTS_IN_TOWN_BUT_YOU                                = 7000,  -- You can buy flowerrrpots in town, but you're gonna have to go out and get your seeds from plant-monsterrrs.
        AND_THEN_GUESS_WHAT_GUESS_GUESS                                         = 7001,  -- And then guess what! Guess! Guess!
        GIVE_YOUR_PLANT_A_CRRRYSTAL_AND_ITS_FRRRUIT                             = 7002,  -- Give your plant a crrrystal and its frrruit will change! Really!
        STARES_OFF_INTO_THE_DISTANCE_2                                          = 7003,  -- stares off into the distance.
        OH_I_WAS_JUST_THINKING_ABOUT_ALL_THE                                    = 7004,  -- Oh! I was just thinking about all the different kinds of fruit and... Purrrrrr...
        YOU_CAN_SIT_BACK_RELAX_AND_DO_ALL                                       = 7005,  -- You can sit back, relax and do all your garrrdening in your Mog House!t
        ALL_YOU_HAVE_TO_DO_IS_TELL_HIM                                          = 7006,  -- All you have to do is tell him what to do, and your moogle will do all the worrrk!t
        BUT_MAKE_SURE_YOU_CHECK_UP_ON_YOUR                                      = 7007,  -- But make sure you check up on your plant sometimes, or it might...
        LOOKS_A_LITTLE_SAD                                                      = 7008,  -- looks a little sad.
        WELL_JUST_CHECK_UP_ON_YOUR_PLANT_EVERY                                  = 7009,  -- Well, just check up on your plant every now and then, okay? Prrromise?
        EVEN_IF_YOU_RE_OFF_ON_AN_ADVENTURRRE                                    = 7010,  -- Even if you're off on an adventurrre somewhere, your moogle will use his special powerrrs to take care of your plant!
        MOOGLES_ARE_SO_COOL                                                     = 7011,  -- Moogles are so cool!
        UM_UM_I_THINK_YOU_CAN_HAVE_UP                                           = 7012,  -- Um, um, I think you can have up to ten plants in yourrr room.
        ANY_MORRRE_AND_YOUR_MOOGLE_WON_T_BE                                     = 7013,  -- Any morrre and your moogle won't be able to handle it! They're rrreally busy, you know!
        AND_OH_YEAH_YOU_HAVE_TO_PUT_YOUR                                        = 7014,  -- And... Oh, yeah! You have to put your seeds and flowerpots in your Mog Safe beforrre you can use 'em!
        THEY_NEED_TO_BE_IN_THERRRE_SO_YOUR                                      = 7015,  -- They need to be in therrre so your moogle can use his magic on 'em!
        MOOGLES_ARE_AWESOME_T                                                   = 7016,  -- Moogles are awesome!t
        I_WISH_I_COULD_FILL_MY_HOUSE_WITH                                       = 7017,  -- I wish I could fill my house with lots of prrretty flowers!
        I_AM_CHARGED_WITH_THE_TASK_OF_ASSISTING                                 = 7018,  -- I am charged with the task of assisting novice adventurers. What would you like to know?
        WHAT_WOULD_YOU_LIKE_TO_KNOW_HOW_DO                                      = 7019,  -- What would you like to know? How do I give items to people? Where can I fight monsters? What are quests and missions? I want to see a map of the city. Nothing for now.
        GIVING_ITEMS_TO_OTHER_PEOPLE_IS_CALLED_TRADING                          = 7020,  -- Giving items to other people is called trading. It is done by selecting Trade from the main menu on the right.
        YOU_MUST_TARGET_THE_PERSON_EITHER_BEFORE_OR                             = 7021,  -- You must target the person either before or after selecting Trade. Then just choose the items you wish to give the person when your inventory window appears.
        TRADING_IS_CRUCIAL_TO_COMPLETING_QUESTS_AND_MISSIONS                    = 7022,  -- Trading is crucial to completing quests and missions, and also during conquests. Remember it well.
        IF_YOU_HAVE_IN_YOUR_POSSESSION_USE_TRADE                                = 7023,  -- If you have % in your possession, use Trade now to give it to me. I will hand you some starting gil in return.
        BEFORE_YOU_TAKE_ON_ANY_FIENDS_THERE_ARE                                 = 7024,  -- Before you take on any fiends, there are a few things you should remember. First, always have weapons and armor equipped, and spells memorized from scrolls.
        SECOND_ALWAYS_CHECK_YOUR_TARGET_BEFORE_ENGAGING_IT                      = 7025,  -- Second, always check your target before engaging it. Never take on a foe that seems too strong for you to defeat alone.
        THIRD_WHEN_YOU_ARE_IN_A_PARTY_MAKE                                      = 7026,  -- Third, when you are in a party, make it a habit to cast lots for your share of the party spoils after successfully defeating a monster.
        SOME_PEOPLE_IN_TOWN_WILL_ASK_YOU_TO                                     = 7027,  -- Some people in town will ask you to do certain tasks for them. These are called quests. Complete them, and they should reward you for your efforts.
        THERE_ARE_ALSO_TASKS_YOU_CAN_DO_FOR                                     = 7028,  -- There are also tasks you can do for your country, known as missions. There is a guard at each gate charged with assigning them. Speak to the guards for more details.
        COME_TO_ME_IF_THERE_IS_ANYTHING_MORE                                    = 7029,  -- Come to me if there is anything more you would like to know.
        GOOD_HERE_IS_YOUR_STARTING_GIL                                          = 7030,  -- %, good. Here is your starting gil.
        HERE_IS_A_MAP_OF_THE_ENTIRE_CITY                                        = 7031,  -- Here is a map of the entire city. You are currently in [the Mines District/the Markets District/Port Bastok/the Metalworks].
        USE_THE_MAP_IN_THE_MAIN_MENU_FOR                                        = 7032,  -- Use the Map in the main menu for a more detailed view of your surroundings.
        YOU_WOULD_DO_WELL_TO_SPEAK_WITH_A                                       = 7033,  -- You would do well to speak with a man named Gulldago. You can find him by the West Gate in Bastok Markets.
        INQUIRE_ABOUT_WHAT_I_WANT_TO_FIND_SOME                                  = 7034,  -- Inquire about what? I want to find some quests! I want to try the tutorial event! Teach me about Records of Eminence! Teach me about the Trust initiative! I want a map of my current area! I want maps of Bastok! How do I give items to people? How do I fight outside town? What are quests and missions? I have other questions. Nothing for now.
        I_CAN_BESTOW_SOME_MAGICAL_MARKINGS_ON_YOUR                              = 7035,  -- I can bestow some magical markings on your map of the Bastok area if you want to know some helpful spots.
        THERE_ARE_VENDORS_THAT_SELL_MAPS_IN_BOTH                                = 7036,  -- There are vendors that sell maps in both Bastok Markets and Port Bastok, but the former is closer.
        THE_MAP_VENDOR_S_IN_ONE_OF_THE                                          = 7037,  -- The map vendor's in one of the tents up that stairway to the north.
        IF_YOU_RE_LOOKING_FOR_SOMEONE_SELLING_MAPS                              = 7038,  -- If you're looking for someone selling maps, head down those stairs to the south and keep going until you reach an open area. The vendor's tent should be there.
        WE_VE_PREPARED_A_VARIETY_OF_INSTRUCTIONAL_TASKS                         = 7039,  -- We've prepared a variety of instructional tasks for Bastokers new to the whole adventuring thing.
        IF_YOU_RE_INTERESTED_TALK_TO_GULLDAGO_NEAR                              = 7040,  -- If you're interested, talk to Gulldago near the gate to South Gustaberg in Bastok Markets.
        FIRST_HEAD_WEST_OF_HERE_THEN_TURN_NORTH                                 = 7041,  -- First, head west of here, then turn north towards a tunnel. Pass through it and you should arrive at the markets.
        HEAD_WEST_OF_HERE_UNTIL_YOU_CAN_T                                       = 7042,  -- Head west of here until you can't go any further, then turn south and cross over Rye Bridge. That should get you to the markets.
        ONCE_YOU_RE_THERE_GO_FIND_GULLDAGO_I                                    = 7043,  -- Once you're there, go find Gulldago. I'll mark him on your map for you.
        TO_CONFIRM_WHAT_YOU_VE_MARKED_SELECT_MARKERS                            = 7044,  -- To confirm what you've marked, select Markers under Map in the main menu, then press the right arrow key.
        YOU_CAN_ALSO_SELECT_WIDE_SCAN_UNDER_THE                                 = 7045,  -- You can also select Wide Scan under the Map submenu to search for people in your vicinity.
        WHETHER_YOU_RE_NEW_TO_VANA_DIEL_OR                                      = 7046,  -- Whether you're new to Vana'diel or a veteran chomping at the bit, Records of Eminence is a great way to easily participate in a variety of content and earn dazzling rewards.
        OPEN_UP_THE_MAIN_MENU_GO_TO_THE                                         = 7047,  -- Open up the main menu, go to the right, and select Objective List under the Quests submenu.
        FROM_THERE_OPEN_UP_THE_TUTORIAL_MENU_AND                                = 7048,  -- From there, open up the Tutorial menu and select Basics, and get started with First Step Forward.
        I_LL_EVEN_GIVE_YOU_A_LITTLE_HINT                                        = 7049,  -- I'll even give you a little hint for completing First Step Forward.
        GO_FORTH_IN_BASTOK_MARKETS_AND_SPEAK_WITH                               = 7050,  -- Go forth in Bastok Markets and speak with the designated individual. Here, let me place a marker on your map.
        RECORDS_OF_EMINENCE_HAS_A_LITTLE_BIT_OF                                 = 7051,  -- Records of Eminence has a little bit of something for everyone, so be sure to give it a go!
        THE_TRUST_INITIATIVE_CONSISTS_OF_A_NEW_TYPE                             = 7052,  -- The Trust initiative consists of a new type of magic developed by one of Vana'diel's most prestigious magical organizations.
        THOSE_WHO_PASS_THE_INITIATION_RITES_AND_FORM                            = 7053,  -- Those who pass the initiation rites and form special bonds will be rewarded with allies to join them on their journeys.
        YOU_MUST_BE_LEVEL_FIVE_OR_GREATER_TO                                    = 7054,  -- You must be level five or greater to participate in the Trust initiative. I'll be glad to guide you once you are.
        CLARION_STAR_IN_PORT_BASTOK_IS_IN_CHARGE                                = 7055,  -- Clarion Star in Port Bastok is in charge of the Trust initiative here in our fair city. Let me mark his location on your map.
        OPENING_THE_MAIN_MENU_AND_PRESSING_THE_RIGHT                            = 7056,  -- Opening the main menu and pressing the right arrow key will bring you to the second page of the menu, where the Help Desk option is.
        SELECT_THAT_THEN_CLICK_THE_HELP_DESK_OPTION                             = 7057,  -- Select that, then click the Help Desk option again in the menu that pops up. After that, one of the categories will be I need help with the game controls.
        IF_YOU_EVER_HAVE_A_PROBLEM_A_QUICK                                      = 7058,  -- If you ever have a problem, a quick look there might help you figure things out.
        CITIZENS_ALL_OVER_THE_REPUBLIC_NEED_YOUR_HELP                           = 7059,  -- Citizens all over the republic need your help. Do you want to search my records to find some of them?
        INQUIRE_ABOUT_WHICH_LOCALE_NONE_BASTOK_MINES_INDIVIDUAL                 = 7060,  -- Inquire about which locale? None. Bastok Mines: # individual[/s]. Bastok Markets: # individual[/s]. Port Bastok: # individual[/s]. Metalworks: # individual[/s].
        TALK_TO_THE_FOLLOWING_PEOPLE_IN_WHO_SHOULD                              = 7061,  -- Talk to the following people in [the mines/the markets/the port/the Metalworks], who should be more than happy to entrust you with some tasks.
        WHO_WILL_YOU_GO_SEE_IN_BASTOK_MINES                                     = 7062,  -- Who will you go see in Bastok Mines? No one. Wahid. Elki. Tami. Gerbaum. Black Mud. Elki. Pavvke. Detzo. Goraow. Gumbah. Gumbah. Virnage. Titus. Phara. Phara. Deidogg. Gumbah. Selliste.
        WHO_WILL_YOU_GO_SEE_IN_BASTOK_MARKETS                                   = 7063,  -- Who will you go see in Bastok Markets? No one. Malene. Salimah. Michea. Aquillina. Arawn. Nbu Latteh. Foss. Degenhard. Offa. Brygid. Horatius. Michea. Nbu Latteh. Marin. Gwill. Zon-Fobun. Enu. Brygid. Shamarhaan.
        WHO_WILL_YOU_GO_SEE_IN_PORT_BASTOK                                      = 7064,  -- Who will you go see in Port Bastok? No one. Powhatan. Corann. Talib. Talib. Alib-Mufalib. Ronan. Valah Molkot. Clarion Star. Gudav. Benita. Evi. Qiji. Yazan. Raifa. Romilda. Agapito. Ensetsu. Kurando. Powhatan. Carmelo. Hilda. Juroro. Trilok. Carmelo. Carmelo. Ferrol. Oggbi. Oggbi. Oggbi. Grin.
        QHT_HILDOLF_WHO_WILL_YOU_GO_SEE_IN                                      = 7065,  -- qht(Hildolf) Who will you go see in the Metalworks? No one. Hungry Wolf. Izabele. Ferghus. Raibaht. Hildolf. Unlucky Rat. Baldric. Mighty Fist. Raibaht. Cid. High Bear. Ayame. Ayame. Raibaht. Ayame. Ayame. Raibaht. Cid. Zeid. Ayame. Iron Eater. Cid.
        LET_ME_MARK_THEIR_POSITION_ON_YOUR_MAP                                  = 7066,  -- Let me mark their position on your map.
        FINALLY_SOME_INFORMATION_TO_HELP_YOU_IN_YOUR                            = 7067,  -- FiNAllY, sOmE InFOrmAtiOn tO hELp yOu In yoUr TrAVelS.
        ONE_MORE_THING                                                          = 7068,  -- One more thing.
        I_HAVE_SAVED_A_RATHER_PARAMOUNT_DETAIL_FOR                              = 7069,  -- I have saved a rather paramount detail for last. Allow me to explain.
        THERE_S_STILL_ONE_OTHER_THING_REMAINING_TO                              = 7070,  -- There's still one other thing remaining to share with you.
        YOU_CAN_WARP_BETWEEN_PLACES_KNOWN_AS_HOME                               = 7071,  -- YoU CAn wArP BetWEen PlACes KnOwn aS HoME pOinTs. TheY ARe moST CoNveNieNT, sO maKe SuRE to ReGIsTer ThEM bY TouCHing ThE SurFaCE.
        HOME_POINTS_WILL_PROBABLY_TURN_OUT_TO_BE                                = 7072,  -- Home points will probably turn out to be among your best companions. Make sure to examine one if you find it, so you can warp between them and cover large distances fast.
        YOU_MAY_TELEPORT_BETWEEN_THESE_CRYSTALLINE_NODES_CALLED                 = 7073,  -- You may teleport between these crystalline nodes called home points for efficient travel. Be sure to examine any you stumble upon.
        THERE_S_SOME_SPECIAL_CRYSTAL_NODES_KNOWN_AS                             = 7074,  -- There's some special crystal nodes known as home points that'll undoubtedly serve you well. Don't forget to interact with all that you find, as they can help you get to far away places.
        IF_YOU_FIND_YOURSELF_IN_A_FARAWAY_PLACE                                 = 7075,  -- If yOU fINd yOurSeLF iN A fARaWay pLaCe, maKe sURe tO FinD a StoRE to BuY a Map fROm! wIth a MaP, yoU CaN ChEck WheRe yOu ArE!
        SHOULD_YOU_FIND_YOURSELF_LOST_IN_THE_MIDDLE                             = 7076,  -- Should you find yourself lost in the middle of nowhere, try to make it back to town to buy a map. That way, you can get your bearings.
        REMEMBER_TO_PURCHASE_A_MAP_FROM_THE_APPROPRIATE                         = 7077,  -- Remember to purchase a map from the appropriate vendor before going to a faraway land. If you do, you can check your location within that place.
        DID_YOU_KNOW_THAT_SOME_VENDORS_WILL_SELL                                = 7078,  -- Did you know that some vendors will sell you maps of specific areas? It sure beats stumbling around like a dullard!
        DON_T_WASTE_PRECIOUS_ITEMS_BY_SELLING_THEM                              = 7079,  -- DoN'T WaSTe pRecIOus iTemS By sEllINg tHeM tO a StoRe. MaKE eVen MoRe MonEy By PuTTing tHeM uP At tHe AucTIon HouSe!
