        ONLY_DEPARTING_PASSENGERS_MAY_PASS_THROUGH_THESE_DOORS                  = 7608,  -- Only departing passengers may pass through these doors. Please go around to the entrance on the south side.
        THOSE_DOORS_LEAD_TO_THE_AIRSHIP_EMBARKATION_AREA                        = 7609,  -- Those doors lead to the airship embarkation area. You must pay # gil to pass through.
        PAY_GIL_YES_NO                                                          = 7610,  -- Pay # gil? Yes. No.
        YOU_CAN_T_GET_OUT_TO_THE_PIER                                           = 7611,  -- You can't get out to the pier this way. Only arriving passengers may go through these doors. Please go around to the entrance on the west side.
        IF_YOU_ENTER_BASTOK_YOU_MUST_PAY_AGAIN                                  = 7612,  -- If you enter Bastok, you must pay again to board the airship. Would you like to proceed?
        GO_IN_YES_NO                                                            = 7613,  -- Go in? Yes. No.
