        BUT_THE_HANDS_OF_THE_CLOCK_WOULD_BREAK                                  = 7663,  -- But the hands of the clock would break... I suppose she is right.
        THANK_YOU_I_CAN_SEE_THINGS_MORE_CLEARLY                                 = 7664,  -- Thank you. I can see things more clearly now... I will keep my clock wound so that when I see her, our times will be the same. Here, take this as a token of my gratitude.
        HI_THERE_FOR_HERE_OR_TO_GO                                              = 7665,  -- Hi, there. For here or to go?
        WELCOME_TO_THE_STEAMING_SHEEP_WOULD_YOU_LIKE                            = 7666,  -- Welcome to the Steaming Sheep. Would you like something to drink?
        HELLO_THIS_CONCOURSE_IS_FOR_ARRIVING_PASSENGERS                         = 7667,  -- Hello. This concourse is for arriving passengers.
        HELLO_THIS_CONCOURSE_IS_FOR_DEPARTING_PASSENGERS                        = 7668,  -- Hello. This concourse is for departing passengers.
        HELLO_MIGHT_I_INTEREST_YOU_IN_SOME_SPECIALTY                            = 7669,  -- Hello! Might I interest you in some specialty goods from Gustaberg?
        WELCOME_TO_GALVIN_S_TRAVEL_GEAR_WE_DO                                   = 7670,  -- Welcome to Galvin's Travel Gear! We do our best to get the best for only the best!
        HELLO_HELLO_WON_T_YOU_BUY_SOMETHING_I                                   = 7671,  -- Hello, hello! Won't you buy something? I'll give you a rebate!
        WELCOME_I_VE_GOT_GOODS_FROM_DERFLAND_INTERESTED                         = 7672,  -- Welcome. I've got goods from Derfland. Interested?
        HELLO_HELLO_EVERYTHING_I_HAVE_IS_IMPORTED_DIRECTLY                      = 7673,  -- Hello, hello! Everything I have is imported directly from Zulkheim!
        HELLO_THERE_HOW_ABOUT_BUYING_TO_STAY_IN                                 = 7674,  -- Hello there. How about buying % to stay in touch with your friends?
        TRAVELER_I_AM_SURE_MY_WARES_WILL_PROVE                                  = 7675,  -- Traveler! I am sure my wares will prove useful on your journey. Why don't you buy some?
        AH_INTERESTED_IN_MY_WARES_ARE_YOU_YOU                                   = 7676,  -- Ah, interested in my wares, are you? You can only buy these in Bastok, my friend.
        HAVE_YOU_EVER_BEEN_TO_SELBINA_IT_S                                      = 7677,  -- Have you ever been to Selbina? It's a harbor town a little way north of Bastok. Many adventurers go there to ride the ferry to Mhaura. You should go there someday.
        I_MAKE_A_LIVING_TRADING_GOODS_WITH_SELBINA                              = 7678,  -- I make a living trading goods with Selbina, you see. But lately, my shipments are having trouble reaching the place.
