        SAY_COULD_YOU_DO_ME_A_FAVOR_AND                                         = 7680,  -- Say, could you do me a favor and beat those flying rats out of the way? If you bring me % as proof you did your job, I'll be more than happy to pay you!
        I_CAN_T_BELIEVE_A_BUNCH_OF_FILTHY                                       = 7681,  -- I can't believe a bunch of filthy flying rodents are the cause of all my troubles...
