        SAY_YOU_LOOK_LIKE_A_SEASONED_ADVENTURER_WHAT                            = 7684,  -- Say, you look like a seasoned adventurer. What say you to taking on a Tenshodo job for a change?
        IF_YOU_SUCCEED_I_WILL_GIVE_YOU_ONLY                                     = 7685,  -- If you succeed, I will give you %. Only veteran monks may use it, but even if you aren't one, you can still sell it for a heap of gil.
