        I_M_TRRRYING_TO_START_A_BUSINESS_SELLING                                = 8403,  -- I'm trrrying to start a business selling goods from the Elshimo Lowlands, but it's not easy getting stuff from areas that aren't under Bastokan contrrrol.
        WELCOME_WELCOME_TAKE_A_WONDERRR_AT_THESE_SPECIALTY                      = 8404,  -- Welcome! Welcome! Take a wonderrr at these specialty goods from the Elshimo Uplands!
