        I_WAS_GOING_TO_WAIT_BUT_I_GUESS                                         = 8441,  -- I was going to wait, but I guess you are old enough to know...
        THIS_DAGGER_WAS_YOUR_MOTHER_S                                           = 8442,  -- This dagger was your mother's...
        YOU_MEAN_THIS_OLD_THING_WAS                                             = 8443,  -- You mean this old thing was...
        MOM_S                                                                   = 8444,  -- Mom's...?
        YES_ITS_REAL_NAME_IS_A_SHINOBI_GATANA                                   = 8445,  -- Yes. Its real name is a shinobi gatana.
        MOM_WAS_A_NINJA                                                         = 8446,  -- Mom was a ninja?
