        THE_HARDSHIPS_THAT_SHE_HAD_TO_ENDURE_MADE                               = 8452,  -- The hardships that she had to endure made her into the strong mother that she was.
        PERHAPS_AT_THAT_TIME_SHE_REALIZED_THAT_SHE                              = 8453,  -- Perhaps at that time, she realized that she did not have much longer in this world...
        BUT_SHE_FOUGHT_FOR_TEN_LONG_YEARS_UNTIL                                 = 8454,  -- But she fought for ten long years until she exchanged her life for the life of our second daughter...you, Kaede.
