        MOM                                                                     = 8464,  -- Mom!
        I_THANK_YOU_SO_MUCH_FOR_YOUR_HELP                                       = 8465,  -- I thank you so much for your help in bringing the blade back to my home. I do not have much to offer you, but take this scroll detailing the secrets of the ninja as a token of my appreciation. It was my wife's.
        NO_KAEDE_WON_T_BE_NEEDING_IT_ALL                                        = 8466,  -- No, Kaede won't be needing it. All she really needed was her mother's strong will and spirit. If she wishes to walk the path Yomi chose, it will be her decision.
        BUT_I_HAVE_THE_FEELING_SHE_WILL_BE                                      = 8467,  -- But I have the feeling she will be traveling to Norg soon...to find that path.
