        WHEN_CARRYING_WITH_YOU_WHILE_PARTICIPATING_IN_A                         = 8952,  -- When carrying % with you while participating in a Ballista match, you will have the option to keep or throw away the first Petra you find. This is useful when you want to continue /sprinting.
        IF_YOU_WISH_I_CAN_LOAN_YOU_ONE                                          = 8953,  -- If you wish, I can loan you one, free of charge.
        BORROW_YES_NO_2                                                         = 8954,  -- Borrow %? Yes. No.
        RETURN_THE_YES_NO_2                                                     = 8955,  -- Return the %? Yes. No.
        WHEN_IN_POSSESSION_OF_THE_KEY_ITEM_TEMPORARY                            = 8956,  -- When in possession of the key item %, temporary items will be automatically added to the player's inventory when quarried.
        WHEN_A_PLAYER_S_INVENTORY_EXCEEDS_THE_MAXIMUM                           = 8957,  -- When a player's inventory exceeds the maximum capacity, any temporary item found will simply be discarded. You can speak to me to borrow or return the shovel at any time.
        BORROW_THE_YES_NO                                                       = 8958,  -- Borrow the %? Yes. No.
        RETURN_THE_YES_NO_3                                                     = 8959,  -- Return the %? Yes. No.
        WHEN_IN_POSSESSION_OF_THE_KEY_ITEM_YOU                                  = 8960,  -- When in possession of the key item %, you will have the choice of keeping or throwing away the first Petra you quarry. You will also retain the ability to sprint.
        YOU_CAN_SPEAK_TO_ME_TO_BORROW_OR                                        = 8961,  -- You can speak to me to borrow or return the band at any time.
        SELECT_A_MATCH_LEVEL_VIEW_ALL_LEVELS_NO                                 = 8962,  -- Select a match level... View all levels. No restriction (# gil per match). Level 60 (# gil per match). Level 50 (# gil per match). Level 40 (# gil per match). Level 30 (# gil per match). Return.
        SELECT_FOR_MORE_INFORMATION_NEXT_RETURN                                 = 8963,  -- Select for more information... , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. % / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] Next. Return.
        MATCH_ENTRY_PERIOD_BEGINS_BRIEFING_BEGINS                               = 8964,  -- <Match #> Entry period begins: Briefing begins:
        I_APOLOGIZE_BUT_YOUR_LEVEL_IS_TOO_LOW                                   = 8965,  -- I apologize, but your level is too low to participate in an official Brenner match.
        OFFICIAL_MATCHES_ARE_SCHEDULED_TO_BEGIN_AT_THE                          = 8966,  -- Official matches are scheduled to begin at the following times: Match 1: Match 2: Match 3:
        TELEPORTATION_TO_THE_ISLE_IS_FREE_OF_CHARGE                             = 8967,  -- Teleportation to the Isle is free of charge, but a participation fee of # gil is required before each match.
        TRAVEL_TO_THE_ISLE_YES_NOT_YET                                          = 8968,  -- Travel to the Isle? Yes. Not yet.
        WHAT_WOULD_YOU_LIKE_TO_KNOW_ABOUT_BASIC                                 = 8969,  -- What would you like to know about? Basic rules. Official/private matches. Flammen-Brenner. Flamme. Match score. Petras and quarrying. Sprint. KO. Return.
        THE_BASIC_RULES_OF_BRENNER_ARE_AS_FOLLOWS                               = 8970,  -- The basic rules of Brenner are as follows:
        FIRST_THE_PARTICIPANTS_DIVIDE_INTO_TWO_TEAMS_EACH                       = 8971,  -- First, the participants divide into two teams. Each side's camp contains the same number of Flammen-Brenner.
        AT_THE_BEGINNING_OF_THE_MATCH_HALF_OF                                   = 8972,  -- At the beginning of the match, half of each side's Flammen-Brenner will be ablaze with Flamme, or flame, while the other half will remain unlit.
        PARTICIPANTS_CAN_SEIZE_A_FLAMME_FROM_THE_OPPOSING                       = 8973,  -- Participants can seize a Flamme from the opposing side's Flammen-Brenner and carry it around the Isle.
        THE_GOAL_IS_TO_STEAL_YOUR_OPPONENT_S                                    = 8974,  -- The goal is to steal your opponent's Flamme and use them to light your side's Flammen-Brenner.
        THE_SIDE_THAT_SUCCEEDS_IN_LIGHTING_ALL_OF                               = 8975,  -- The side that succeeds in lighting all of its Flammen-Brenner will be declared the winner after a specified amount of time.
        IF_NEITHER_SIDE_IS_VICTORIOUS_BEFORE_THE_MATCH                          = 8976,  -- If neither side is victorious before the match ends, the outcome will be judged based on the score. The match score section of the rulebook contains more information on this subject.
        BRENNER_IS_SIGNIFICANTLY_DIVIDED_INTO_PUBLIC_AND_PRIVATE                = 8977,  -- Brenner is significantly divided into public and private matches. Official matches are held periodically according to level and feature general participation.
        YOU_CANNOT_RESERVE_THE_ISLE_WHEN_AN_OFFICIAL                            = 8978,  -- You cannot reserve the Isle when an official match is being held.
        NO_ITEMS_ARE_NECESSARY_FOR_PARTICIPATION_BUT_A                          = 8979,  -- No items are necessary for participation, but a minor fee will be collected. You will be unable to participate if your level is too low.
        THE_MATCH_OUTCOME_WILL_BE_RECORDED_UNLESS_THE                           = 8980,  -- The match outcome will be recorded unless the number of participants fails to exceed # members, or if there are fewer than # members in a match where the two sides' numbers differ. In such cases, the game will be considered a training match and will not be recorded.
        PRIVATE_MATCHES_REQUIRE_A_RESERVATION_AND_PARTICIPATION_MAY             = 8981,  -- Private matches require a reservation, and participation may be limited. The Master of Ceremonies (MC) can freely adjust the rules and control match proceedings.
        LS_LIGA_IS_A_FORM_OF_PRIVATE_MATCH                                      = 8982,  -- LS Liga is a form of private match. You can learn more about LS Liga by speaking to a Marshal.
        A_FLAMMEN_BRENNER_IS_A_DEVICE_THAT_CONTAINS                             = 8983,  -- A Flammen-Brenner is a device that contains a Flamme (flame). The Flammen-Brenner is covered by a grate that will open after taking a set amount of damage, exposing the Flamme.
        THE_PARTICIPANTS_MUST_UTILIZE_THIS_CHANCE_TO_SEIZE                      = 8984,  -- The participants must utilize this chance to seize the Flamme before the grate recloses. Once the grate is closed, the Flammen-Brenner will begin recovering from the damage it has been dealt.
        IF_YOU_MANAGE_TO_OPEN_THE_OPPOSING_TEAM                                 = 8985,  -- If you manage to open the opposing team's Flammen-Brenner and capture their Flamme, you should make haste to light one of the Flammen-Brenner on your side.
        AFTER_A_CERTAIN_AMOUNT_OF_TIME_THE_FLAMME                               = 8986,  -- After a certain amount of time, the Flamme will burn out and the opposing team's Flammen-Brenner will be relit.
        ALSO_PLEASE_NOTE_THAT_YOU_CANNOT_QUICKEN_YOUR                           = 8987,  -- Also, please note that you cannot quicken your pace using any special abilities while you are in possession of a Flamme.
        IN_THE_EVENT_THAT_NEITHER_SIDE_FULFILLS_THE                             = 8988,  -- In the event that neither side fulfills the conditions for victory, the outcome of the match will be evaluated based on score.
        TEN_POINTS_ARE_AWARDED_TO_EACH_SIDE_FOR                                 = 8989,  -- Ten points are awarded to each side for every lit Flammen-Brenner, while one point is awarded whenever a Flamme is captured, used to light a Flammen-Brenner, or recaptured from an opponent. One point is also awarded for protecting the Flammen-Brenner for a certain period of time.
        LIKE_BALLISTA_QUARRY_QUARRY_CAN_BE_USED_WHILE                           = 8990,  -- Like Ballista, quarry (/quarry) can be used while playing Brenner. Participants may use this ability to dig up Petras and temporary items.
        HOWEVER_UNLIKE_BALLISTA_PETRAS_BRENNER_PETRAS_HAVE_NO                   = 8991,  -- However, unlike Ballista Petras, Brenner Petras have no effect on the match score. You can trade a Petra to a Pursuivant to recover your HP and MP at no expense to TP.
        SPRINT_CANNOT_BE_USED_WHILE_CARRYING_A_PETRA                            = 8992,  -- Sprint cannot be used while carrying a Petra. Also, please note that the scout ability cannot be used in Brenner.
        PETRAS_WILL_BE_LOST_IN_THE_EVENT_OF                                     = 8993,  -- Petras will be lost in the event of a KO, but can be carried over from one match to another.
        THE_SPRINT_SPRINT_ABILITY_CAN_BE_USED_TO                                = 8994,  -- The sprint (/sprint) ability can be used to increase the player's speed when not in possession of a Flamme or Petras.
        IN_THE_EVENT_OF_A_KO_YOU_WILL                                           = 8995,  -- In the event of a KO, you will be returned to your team's camp. However, recovery will take longer the more often you fall in battle.
        IN_OTHER_WORDS_YOU_WILL_RECEIVE_A_PENALTY                               = 8996,  -- In other words, you will receive a penalty if you fall immediately after recovering from KO. In addition, your TP will be reduced to zero and you will lose any Petras in your possession.
        I_M_SORRY_I_WASN_T_LISTENING_COULD                                      = 8997,  -- I'm sorry. I wasn't listening. Could you start over from the beginning?
        WHAT_DO_YOU_WISH_TO_KNOW_ABOUT_BASIC                                    = 8998,  -- What do you wish to know about? Basic rules. About the Petra. About Sprint. About Scout. About Gate Breach. About area-specific rules. About returning to battle. About special rules. Nothing at the moment.
        BALLISTA_IS_AN_EXERCISE_ONCE_USED_BY_THE                                = 8999,  -- Ballista is an exercise once used by the San d'Orian armies to train the Royal Knights in the art of the siege. The word ballista means to throw a stone, and the game has been a part of Vana'dielian military history for centuries.
        THE_RULES_ARE_SIMPLE_BALLISTA_IS_PLAYED_BY                              = 9000,  -- The rules are simple. Ballista is played by two teams over a number of hours (Vana'diel time). The team with the most points at the end of the match is the victor.
        PLAYERS_FROM_BOTH_TEAMS_MUST_SEARCH_FOR_PETRAS                          = 9001,  -- Players from both teams must search for Petras that a Herald has buried in various locations across the battlefield. The players must then take these stones and throw them into targets known as Rooks.
        THESE_ROOKS_CAN_APPEAR_IN_VARIOUS_LOCATIONS_AROUND                      = 9002,  -- These Rooks can appear in various locations around the battlefield, and both teams are allowed to throw their Petras into them.
        FINALLY_A_PLAYER_S_STRENGTH_IS_ADJUSTED_DEPENDING                       = 9003,  -- Finally, a player's strength is adjusted depending on his or her level. It is felt that this ultimately allows for a more balanced battle.
        PETRAS_CAN_BE_BURIED_ANYWHERE_ONCE_A_PLAYER                             = 9004,  -- Petras can be buried anywhere. Once a player believes he or she has found one, the Quarry (/quarry) command should be used to dig up the area at his or her feet.
        SOMETIMES_A_PLAYER_MAY_FIND_ITEMS_OTHER_THAN                            = 9005,  -- Sometimes a player may find items other than Petras, such as potions. These temporary items can only be used during the current match (or Best of Three series).
        PLAYERS_CAN_CARRY_MORE_THAN_ONE_PETRA_BUT                               = 9006,  -- Players can carry more than one Petra, but they cannot throw the stones away once they have obtained them. However, players will lose their Petras if they: (1) Successfully throw them into a rook. (2) Leave the area. (3) Are knocked out.
        BUT_DON_T_FORGET_A_PLAYER_WILL_BE                                       = 9007,  -- But don't forget, a player will be unable to use the Sprint command while in possession of a Petra. And, players can only use the Scout command if they carry one of the stones.
        AS_ONE_CAN_SEE_CAREFUL_PLANNING_AND_IMPECCABLE                          = 9008,  -- As one can see, careful planning and impeccable timing are the keys to victory.
        ALL_PARTICIPANTS_OF_BALLISTA_WILL_HAVE_THE_ABILITY                      = 9009,  -- All participants of Ballista will have the ability to use the Sprint command. This will temporarily increase one's movement speed, creating a better chance to find and obtain Petras.
        HOWEVER_REMEMBER_THAT_ONCE_A_PLAYER_HAS_OBTAINED                        = 9010,  -- However, remember that once a player has obtained a Petra, he or she will be unable to use the Sprint command. In its place, though, one may use the Scout command.
        THE_LOCATIONS_OF_THE_ROOKS_ARE_CONSTANTLY_CHANGING                      = 9011,  -- The locations of the Rooks are constantly changing. This makes it quite difficult to find the targets by just randomly walking about the area.
        COMMUNICATION_WITH_ONE_S_TEAM_MEMBERS_IS_OF                             = 9012,  -- Communication with one's team members is, of course, one way to locate Rooks. However, another way is by using the Scout command. This will inform a player of the approximate location of the nearest Rook.
        FINALLY_SCOUT_CAN_ONLY_BE_USED_WHEN_A                                   = 9013,  -- Finally, Scout can only be used when a player is carrying a Petra. Because Sprint cannot be used at this time, players must be weary of approaching enemies.
        SO_A_PETRA_HAS_BEEN_OBTAINED_AND_A                                      = 9014,  -- So, a Petra has been obtained and a Rook located. Now all that's left is tossing the stone in, right? Wrong.
        THERE_IS_ONE_ASPECT_OF_BALLISTA_THAT_HAS                                = 9015,  -- There is one aspect of Ballista that has yet to be mentioned...and this is where the real battle begins.
        TO_THROW_A_PETRA_INTO_A_ROOK_A                                          = 9016,  -- To throw a Petra into a Rook, a player must first wait until the Rook's gate is open. This takes impeccable timing, as the gate is only open for a short while.
        BUT_NOT_JUST_ANYONE_CAN_SCORE_POINTS_THIS                               = 9017,  -- But not just anyone can score points this way. A player must first take down a member of the opposing team and achieve Gate Breach status. Only then will his or her shots count.
        THIS_EXTREME_METHOD_OF_COMBAT_IS_WHAT_MADE                              = 9018,  -- This extreme method of combat is what made the ancient game of Ballista famous, and transformed its participants into heroes.
        RUNNING_ABOUT_LOOKING_FOR_STONES_IS_NO_DIFFERENT                        = 9019,  -- Running about looking for stones is no different from a child's game of hide-and-seek. Knowing when to strike is what separates the men from the boys.
        THE_FOLLOWING_MATCH_TYPES_ARE_AREA_SPECIFIC_ALL                         = 9020,  -- The following match types are area-specific: All or Nothing (one match) * Normal Items Allowed: Jugner Forest All or Nothing (one match) * Normal Items Restricted: Pashhow Marshlands Best of Three (three matches) * Normal Items Allowed: Meriphataud Mountains
        BEST_OF_THREE_SERIES_RULES_ARE_AS_FOLLOWS                               = 9021,  -- Best of Three series rules are as follows: Winning a match will earn a nation one match point. The nation with the most match points at the end of the series will be declared the victor. Winning the third and final match and producing the high scorer will result in two match points awarded. This allows both sides the chance for come-from-behind victories.
        BETWEEN_EACH_OF_THE_MATCHES_A_SHORT_INTERVAL                            = 9022,  -- Between each of the matches, a short interval will be implemented. During this interval, Invisible and Sneak will be cast on all participants. We suggest this time be used to discuss strategies with the other members of your nation's forces.
        PLAYERS_WILL_BE_FORBIDDEN_FROM_USING_ANY_ITEMS                          = 9023,  -- Players will be forbidden from using any items they bring to the battlefield. Only temporary items that are quarried may be used. A total of fifteen temporary items (though only one of each type) can be carried.
        WHEN_THIS_RULE_IS_IN_EFFECT_ALL_PLAYERS                                 = 9024,  -- When this rule is in effect, all players will be presented with five complimentary temporary items at the beginning of the match.
        FOR_MORE_INFORMATION_ON_TEMPORARY_ITEMS_REFER_TO                        = 9025,  -- For more information on temporary items, refer to the special rules.
        AFTER_BEING_KO_D_IF_A_PLAYER_CHOOSES                                    = 9026,  -- After being KO'd, if a player chooses to be revived at the spot he was defeated, 100% of all HP and 50% of all MP will be restored. In addition, the player will maintain 50% of the TP he had earned.
        IF_A_PLAYER_CHOOSES_TO_RETURN_TO_THEIR                                  = 9027,  -- If a player chooses to return to their force's camp, HP and MP will be fully restored, but all TP will be lost.
        PLEASE_NOTE_THAT_MANY_OF_THE_RULES_PREVIOUSLY                           = 9028,  -- Please note that many of the rules previously considered special have been fully implemented. Also, several new special rules have been added.
        LEARN_ABOUT_WHICH_SPECIAL_RULES_TEMPORARY_ITEMS_BALLISTA                = 9029,  -- Learn about which special rules? Temporary items. Ballista Points. Scoring restrictions. Gate Breach radius expansion. Resistance to Sleep. Open entries. Minimum level restrictions. Re-entry restrictions. Participant & Rook numbers. Experience Points. Return.
        PREVIOUSLY_PARTICIPANTS_IN_BALLISTA_WERE_REQUIRED_TO_USE                = 9030,  -- Previously, participants in Ballista were required to use an item the moment they dug it up using the /quarry command. However, players can now stock these items as temporary items for use at any time during the match.
        PLAYERS_CAN_HOLD_UP_TO_TEN_TEMPORARY_ITEMS                              = 9031,  -- Players can hold up to ten temporary items, but only one of each type. If a player finds an item that they already possess, they must use it immediately or throw it away.
        IF_PLAYERS_WHO_POSSESS_TEN_TEMPORARY_ITEMS_FIND                         = 9032,  -- If players who possess ten temporary items find an item that they have not already obtained, they will also have the option to exchange it with one of their current items.
        ALSO_PLAYERS_WILL_NOT_AT_ANY_TIME_BE                                    = 9033,  -- Also, players will not, at any time, be allowed to trade temporary items. However, there are items that can be used on other Ballista participants. Please note that players may not be able to use these special items as soon as they are quarried.
        FINALLY_THE_HERALDS_WILL_COLLECT_TEMPORARY_ITEMS_WHEN                   = 9034,  -- Finally, the Heralds will collect temporary items when the match (the third in a Best of Three series) has concluded.
        BALLISTA_POINTS_ARE_REWARDED_TO_EACH_COMPETITOR_BASED                   = 9035,  -- Ballista Points are rewarded to each competitor based on his or her performance in a single Ballista match. The maximum number of points that can be accumulated per match is #.
        WHILE_IT_IS_TAKEN_INTO_CONSIDERATION_SCORING_PETRAS                     = 9036,  -- While it is taken into consideration, scoring Petras is not the only way to earn Ballista Points. Assisting allies and defeating members of the enemy forces can also earn a high score.
        BALLISTA_POINTS_CAN_BE_TRADED_FOR_SPECIAL_VOUCHERS                      = 9037,  -- Ballista Points can be traded for special vouchers, which may be exchanged for free temporary items at the start of new matches.
        HOWEVER_REMEMBER_THAT_DEPENDING_ON_THE_LEVEL_RESTRICTION                = 9038,  -- However, remember that depending on the level restriction of the match, certain vouchers will not be redeemed at the beginning of a match. Speak with a Marshal directly after a match to register your points.
        PLAYERS_WILL_ONLY_BE_ALLOWED_TO_SCORE_UP                                = 9039,  -- Players will only be allowed to score up to five Petras at a time. Also, a player's Gate Breach status will be automatically disengaged if a Petra is not scored within a certain amount of time. The amount of time is increased for those members of the team currently behind in points.
        ALL_ALLIES_WITHIN_A_CERTAIN_RADIUS_WILL_ACHIEVE                         = 9040,  -- All allies within a certain radius will achieve Gate Breach status when a member of the enemy forces is defeated.
        PLAYERS_RESISTANCE_TO_SLEEP_WILL_BE_INCREASED                           = 9041,  -- Players' resistance to sleep will be increased.
        DURING_THE_ENTRY_PERIOD_FROM_ALL_ADVENTURERS_WILL                       = 9042,  -- During the entry period, from #:, all adventurers will be allowed to join the forces with the smallest number of participants, regardless of allegiance. Open entries will be accepted until both sides have reached maximum capacity.
        IN_ORDER_TO_ENSURE_BALANCED_MATCHES_THE_FOLLOWING                       = 9043,  -- In order to ensure balanced matches, the following level limits are enforced: Level 30 matches: 1`30
        LEVEL_40_MATCHES_31_40_LEVEL_50_MATCHES                                 = 9044,  -- Level 40 matches: 31`40 Level 50 matches: 41`50 Level 60 matches: 51`60 Unrestricted matches: 61`
        PLEASE_NOTE_THAT_ANY_PARTICIPANT_WHO_CANCELS_HIS                        = 9045,  -- Please note that any participant who cancels his or her registration will not be allowed to re-apply for the same match.
        WHEN_THE_TOTAL_NUMBER_OF_PARTICIPANTS_IN_A                              = 9046,  -- When the total number of participants in a match is less than 40, the location of the two camps will be adjusted. Also in this case, the number of Rooks will be reduced to two.
        ANY_ADVENTURER_WHOSE_MAIN_LEVEL_IS_OVER_30                              = 9047,  -- Any adventurer whose main level is over 30 will receive EXP for participating in a Ballista match. However, no EXP will be rewarded if the adventurer fails to actively take part in the match.
        READ_WHICH_CHAPTER_ON_B_P_RANKING_BASIC                                 = 9048,  -- Read which chapter on B.P. Ranking? Basic Information. Registering Points. Rewards. Chevron & Title List. None.
        BALLISTA_POINT_RANKING_IS_BASED_UPON_ALL_BALLISTA                       = 9049,  -- Ballista Point Ranking is based upon all Ballista Points registered from the past ten matches in each of the three participating battle areas.
        ANYONE_WHO_WISHES_TO_TAKE_PART_IN_THE                                   = 9050,  -- Anyone who wishes to take part in the ranking needs to register his/her] points within four hours (Vana'diel time) from the end of the previous match.
        AFTER_THE_REGISTRATION_PERIOD_ENDS_PLAYERS_CAN_COMPARE                  = 9051,  -- After the registration period ends, players can compare their record with those of the previous nine matches.
        IF_AT_ANY_TIME_A_PLAYER_RANKS_IN                                        = 9052,  -- If, at any time, a player ranks in the top ten (overall) or first for a specific job, he/she] will have the opportunity to receive a special chevron as well as a new title.
        THERE_ARE_FOUR_TYPES_OF_CHEVRONS_AND_TITLES                             = 9053,  -- There are four types of chevrons and titles awarded to top-ten players (gold/mythril/silver/bronze), as well as twenty-two different types awarded for outstanding performances by players of each of the twenty-two jobs.
        WEARING_A_CHEVRON_DURING_A_BALLISTA_MATCH_WILL                          = 9054,  -- Wearing a chevron during a Ballista match will automatically change a player's current title. If a player wishes to possess this title after a match as well, he/she] must contact a certain bard in San d'Oria.
        ALSO_WHILE_WEARING_A_CHEVRON_PLAYERS_WILL_BE                            = 9055,  -- Also, while wearing a chevron, players will be able to trade Ballista Points for temporary items not available to all players.
        HOWEVER_THE_RULES_OF_BALLISTA_STATE_THAT_PLAYERS                        = 9056,  -- However, the rules of Ballista state that players may only possess a certain chevron for no longer than one half Vana'diel year. When that time comes, they are required to return the chevron before being allowed to participate in any further matches.
        FINALLY_CHECKING_SOMEONE_DURING_A_BALLISTA_MATCH_WILL                   = 9057,  -- Finally, checking someone during a Ballista match will display the total number of chevrons that person has accumulated to date.
        VIEW_WHICH_CHEVRON_TITLE_1ST_OVERALL_2ND_OVERALL                        = 9058,  -- View which chevron/title? 1st (overall). 2nd (overall). 3rd (overall). 4th-10th (overall). 1st (warrior). 1st (monk). 1st (white mage). 1st (black mage). 1st (red mage). 1st (thief). 1st (paladin). 1st (dark knight). 1st (beastmaster). 1st (bard). 1st (ranger). 1st (samurai). 1st (ninja). 1st (dragoon). 1st (summoner). 1st (blue mage). 1st (corsair). 1st (puppetmaster). 1st (dancer). 1st (scholar). 1st (geomancer). 1st (rune fencer). Return.
        KEY_ITEM_TITLE_GOLD_BALLITAR                                            = 9059,  -- Key Item: % Title: Gold Ballitar
        KEY_ITEM_TITLE_MYTHRIL_BALLITAR                                         = 9060,  -- Key Item: % Title: Mythril Ballitar
        KEY_ITEM_TITLE_SILVER_BALLITAR                                          = 9061,  -- Key Item: % Title: Silver Ballitar
        KEY_ITEM_TITLE_BRONZE_BALLITAR                                          = 9062,  -- Key Item: % Title: Bronze Ballitar
        KEY_ITEM_TITLE_SEARINGTAR                                               = 9063,  -- Key Item: % Title: Searingtar
        KEY_ITEM_TITLE_STRIKINGTAR                                              = 9064,  -- Key Item: % Title: Strikingtar
        KEY_ITEM_TITLE_SOOTHINGTAR                                              = 9065,  -- Key Item: % Title: Soothingtar
        KEY_ITEM_TITLE_SABLETAR                                                 = 9066,  -- Key Item: % Title: Sabletar
        KEY_ITEM_TITLE_SCARLETTAR                                               = 9067,  -- Key Item: % Title: Scarlettar
        KEY_ITEM_TITLE_SONICTAR                                                 = 9068,  -- Key Item: % Title: Sonictar
        KEY_ITEM_TITLE_SAINTLYTAR                                               = 9069,  -- Key Item: % Title: Saintlytar
        KEY_ITEM_TITLE_SHADOWYTAR                                               = 9070,  -- Key Item: % Title: Shadowytar
        KEY_ITEM_TITLE_SAVAGETAR                                                = 9071,  -- Key Item: % Title: Savagetar
        KEY_ITEM_TITLE_SINGINGTAR                                               = 9072,  -- Key Item: % Title: Singingtar
        KEY_ITEM_TITLE_SNIPINGTAR                                               = 9073,  -- Key Item: % Title: Snipingtar
        KEY_ITEM_TITLE_SLICINGTAR                                               = 9074,  -- Key Item: % Title: Slicingtar
        KEY_ITEM_TITLE_SNEAKINGTAR                                              = 9075,  -- Key Item: % Title: Sneakingtar
        KEY_ITEM_TITLE_SPEARINGTAR                                              = 9076,  -- Key Item: % Title: Spearingtar
        KEY_ITEM_TITLE_SUMMONINGTAR                                             = 9077,  -- Key Item: % Title: Summoningtar
        KEY_ITEM_TITLE_SAPPHIRETAR                                              = 9078,  -- Key Item: % Title: Sapphiretar
        KEY_ITEM_TITLE_SURGINGTAR                                               = 9079,  -- Key Item: % Title: Surgingtar
