        THIS_IS_THE_BASIC_CARE_PLAN_FOR_YOUR                                    = 10333,  -- This is the basic care plan for your chocobo. Under this plan, we will provide for your chocobo's most fundamental needs.
        YOU_CAN_CHOOSE_TO_GIVE_YOUR_CHOCOBO_A                                   = 10334,  -- You can choose to give your chocobo a long rest. This will revitalize its energy and accelerate its recovery from injury or illness.
        WE_CAN_TAKE_YOUR_CHOCOBO_OUT_ON_A                                       = 10335,  -- We can take your chocobo out on a walk through the safe areas of town. This should improve its physical condition.
        LISTENING_TO_MUSIC_WILL_MAKE_YOUR_CHOCOBO_A                             = 10336,  -- Listening to music will make your chocobo a more refined creature, and should improve its mental condition.
        EXERCISING_ALONE_WILL_IMPROVE_YOUR_CHOCOBO_S_STRENGTH                   = 10337,  -- Exercising alone will improve your chocobo's strength, but will have a slightly negative effect on its mental condition.
        EXERCISING_IN_A_GROUP_WILL_IMPROVE_YOUR_CHOCOBO                         = 10338,  -- Exercising in a group will improve your chocobo's stamina, but will have a slightly negative effect on its mental condition.
        INTERACTING_WITH_CHILDREN_WILL_IMPROVE_YOUR_CHOCOBO_S                   = 10339,  -- Interacting with children will improve your chocobo's intelligence, but will have a slightly negative effect on its physical condition.
        INTERACTING_WITH_OTHER_CHOCOBOS_WILL_IMPROVE_YOUR_CHOCOBO               = 10340,  -- Interacting with other chocobos will improve your chocobo's receptivity, but will have a slightly negative effect on its physical condition.
        YOU_CAN_EARN_SOME_MONEY_BY_HAVING_YOUR                                  = 10341,  -- You can earn some money by having your chocobo deliver packages for the guilds.
        CARRYING_HEAVY_LOADS_WILL_IMPROVE_ITS_PHYSICAL_CONDITION                = 10342,  -- Carrying heavy loads will improve its physical condition, but will inflict a certain amount of stress on the animal.
        YOU_CAN_EXHIBIT_YOUR_CHOCOBO_TO_THE_PUBLIC                              = 10343,  -- You can exhibit your chocobo to the public. We will provide you with a monetary token of gratitude for this service.
        INTERACTING_WITH_THE_PUBLIC_WILL_IMPROVE_ITS_MENTAL                     = 10344,  -- Interacting with the public will improve its mental condition, but will inflict a certain amount of stress on the animal.
        YOU_CAN_SEND_YOUR_CHOCOBO_TO_DELIVER_OFFICIAL                           = 10345,  -- You can send your chocobo to deliver official messages. The nation will compensate you for your services.
        CARRYING_SOMEONE_ON_ITS_BACK_FOR_A_LONG                                 = 10346,  -- Carrying someone on its back for a long period of time will build strength in your chocobo's legs, but will place some strain on the animal.
        YOU_CAN_SEND_YOUR_CHOCOBO_TO_DIG_FOR                                    = 10347,  -- You can send your chocobo to dig for items to benefit the stables. We will thank you for your contribution with a certain amount of gil.
        DIGGING_FOR_TREASURE_WILL_IMPROVE_YOUR_CHOCOBO_S                        = 10348,  -- Digging for treasure will improve your chocobo's intelligence, but will place some strain on the animal and may decrease its stamina.
        YOUR_CHOCOBO_CAN_EVEN_APPEAR_IN_PLAYS_THIS                              = 10349,  -- Your chocobo can even appear in plays. This will require your chocobo to perform simple acts and will improve its receptivity.
        YOU_WILL_RECEIVE_A_GIL_PAYMENT_FOR_THIS                                 = 10350,  -- You will receive a gil payment for this service, but appearing in a play will have a negative effect on the animal's strength and will place some strain on your chocobo.
