        WELCOME_TO_THE_CHOCOBO_RACING_ASSOCIATION_S_CRA                         = 11709,  -- Welcome to the Chocobo Racing Association's (CRA) [San d'Oria/Bastok/Windurst] branch. This service desk is here to accommodate our beginning and intermediate racers.
        I_AM_SORRY_BUT_THERE_ARE_NO_RACES                                       = 11710,  -- I am sorry, but there are no races scheduled at the moment.
        PARTICIPATION_IN_OUR_ORGANIZATION_S_RACES_REQUIRES_THAT                 = 11711,  -- Participation in our organization's races requires that you either possess % or currently have your own full-grown chocobo.
        HOW_ABOUT_YOU_SIR_MA_AM                                                 = 11712,  -- How about you, sir/ma'am]?
        IF_POSSIBLE_WE_WOULD_LIKE_YOU_TO_JOIN                                   = 11713,  -- If possible, we would like you to join us, and help show those trainers in [Bastok and Windurst/San d'Oria and Windurst/San d'Oria and Bastok] which racing team is truly the best in Vana'diel.
        WHAT_DO_YOU_SAY_TELL_ME_MORE_SIGN                                       = 11714,  -- What do you say? Tell me more. Sign me up! Not today.
        CONGRATULATIONS_YOU_ARE_NOW_AN_OFFICIAL_MEMBER_OF                       = 11715,  -- Congratulations, %! You are now an official member of the CRA's [San d'Oria/Bastok/Windurst] racing team.
        I_SEE_PLEASE_COME_BACK_IF_YOU_EVER                                      = 11716,  -- I see. Please come back if you ever change your mind!
        WHAT_WOULD_YOU_LIKE_TO_KNOW_WHY_RACE                                    = 11717,  -- What would you like to know? Why race chocobos, anyway? How do I register for a race? How do I prepare for a race? What are chocobucks? What kind of races are there? What are racing teams? Quit. Return.
        WHY_NOT_OUR_ORIGINAL_PLAN_WAS_TO_ESTABLISH                              = 11718,  -- Why not!? Our original plan was to establish locations across Vana'diel where people could test their birds' skills.
        WE_FELT_THAT_THIS_WOULD_HELP_US_MAINTAIN                                = 11719,  -- We felt that this would help us maintain breeder motivation, which in turn would ensure healthier, happier chocobos. A win-win situation, as we like to call it in the business.
        HOWEVER_AS_RUMORS_OF_THESE_NEW_FACILITIES_BEGAN                         = 11720,  -- However, as rumors of these new facilities began to leak out into the world, people began speculating about the possibility of officially sanctioned chocobo races...
        THE_VCS_COULD_NOT_IGNORE_THE_VOICE_OF                                   = 11721,  -- The VCS could not ignore the voice of the masses, and it was not long before a meeting was held, a vote was taken, and the CRA was formed.
        AND_THAT_S_WHY_I_M_HERE_TRYING                                          = 11722,  -- And that's why I'm here, trying to enlist you and other top breeders into our noble ranks.
        OH_AND_FOR_OUR_MORE_SEASONED_VETERANS_WHO                               = 11723,  -- Oh, and for our more seasoned veterans who feel there are no challenges left for them here at the track, the CRA has finished preparing a new race. And rumor has that it's a doozie!
        FIRST_OF_ALL_YOUR_CHOCOBO_MUST_BE_FULLY                                 = 11724,  -- First of all, your chocobo must be fully grown. It doesn't matter if you are still tending to it, or if it has been sent to pasture, as long as it is large enough to ride.
        NEXT_YOU_MUST_BRING_ME_EITHER_OR_THIS                                   = 11725,  -- Next, you must bring me either % or %. This is all I will require. There are no hidden fees.
        AS_YOUR_CHOCOBO_DEVELOPS_BE_SURE_TO_RE                                  = 11726,  -- As your chocobo develops, be sure to re-register it. This will ensure that your steed is provided with the equipment that most suits its current condition.
        FINALLY_YOU_MAY_ONLY_REGISTER_ONE_CHOCOBO_AT                            = 11727,  -- Finally, you may only register one chocobo at a time, but are free to register a new bird whenever you wish. You need only speak with me to make any necessary changes.
        ONCE_YOU_HAVE_REGISTERED_YOUR_CHOCOBO_AND_ENTERED                       = 11728,  -- Once you have registered your chocobo and entered it in a competition, the CRA will proceed in assigning it a licensed jockey.
        BEFORE_EACH_RACE_YOU_WILL_BE_GIVEN_THE                                  = 11729,  -- Before each race you will be given the opportunity to give the jockey specific orders on his or her riding style.
        IN_ADDITION_TO_THESE_ORDERS_YOU_CAN_ALSO                                = 11730,  -- In addition to these orders, you can also provide the jockey with items to use while riding, as well as equipment to improve your chocobo's performance.
        BEFORE_A_RACE_YOU_CAN_ALSO_CHECK_THE                                    = 11731,  -- Before a race, you can also check the strengths and weaknesses of the other participating chocobos. It is recommended that you use this data when deciding on what orders to give, or which items to equip.
        DEPENDING_ON_YOUR_CHOCOBO_S_PERFORMANCE_IN_SELECT                       = 11732,  -- Depending on your chocobo's performance in select CRA-sanctioned races, you may or may not receive a prize consisting of VCS-mint chocobucks.
        CHOCOBUCKS_CAN_BE_USED_TO_PURCHASE_ITEMS_AS                             = 11733,  -- Chocobucks can be used to purchase items, as well as upgrade your mount. Chocobucks are also required to participate in official races.
        CURRENTLY_PLAYERS_CAN_EARN_UP_TO_BUT_NO                                 = 11734,  -- Currently, players can earn up to, but no more than, 1000 chocobucks. However, this may change without notice.
        THERE_ARE_TWO_MAIN_TYPES_OF_RACES                                       = 11735,  -- There are two main types of races.
        THE_FIRST_TYPE_IS_CALLED_AN_OFFICIAL_RACE                               = 11736,  -- The first type is called an official race. To participate in one of these, you will require chocobucks.
        PLACING_IN_AN_OFFICIAL_RACE_WILL_EARN_YOU                               = 11737,  -- Placing in an official race will earn you gil. The more races you complete, the more respected you will become in the breeder community.
        YOU_MAY_ALSO_TAKE_PART_IN_AN_OFFICIAL                                   = 11738,  -- You may also take part in an official race as often as needed to complete the specified objectives.
        HOWEVER_AFTER_SOME_OF_THE_MORE_GRUELING_RACES                           = 11739,  -- However, after some of the more grueling races, you may be required to wait before entering the next. This is to give your chocobo, as well as the others, an opportunity to rest before running again.
        THE_SECOND_TYPE_OF_RACE_IS_CALLED_A                                     = 11740,  -- The second type of race is called a free run. Unlike the official races, these can be run at any time, regardless of the results of a previous match.
        YOU_MUST_PAY_A_FEE_IN_GIL_TO                                            = 11741,  -- You must pay a fee in gil to participate in free runs, but you will have the opportunity to earn chocobucks depending on your chocobo's performance. You can join as many free runs as you wish in a single day (Earth time), but extra fees may be required for each additional race. (Stable hands have to make a living, too!)
        THE_CRA_IS_SPLIT_UP_INTO_THREE_RACING                                   = 11742,  -- The CRA is split up into three racing teams representing Bastok, Windurst, and San d'Oria.
        EACH_TEAM_HAS_ITS_OWN_SKILLED_JOCKEYS_AND                               = 11743,  -- Each team has its own skilled jockeys, and offers unique services that cannot be obtained at the other two.
        BREEDERS_ARE_ALLOWED_TO_REGISTER_WITH_ANY_TEAM                          = 11744,  -- Breeders are allowed to register with any team they like, and may change their affiliation at any time.
        IN_THE_EVENT_THAT_YOU_WISH_TO_LEAVE                                     = 11745,  -- In the event that you wish to leave a racing team, all official race results, as well as earned chocobucks, will be saved.
        YOU_NEVER_HAVE_TO_WORRY_THAT_YOUR_PAST                                  = 11746,  -- You never have to worry that your past accomplishments may be deleted and lost forever. You only need rejoin the team to restore all your old data.
        ANYWAY_THERE_IS_NO_HARM_IN_VISITING_ALL                                 = 11747,  -- Anyway, there is no harm in visiting all three racing teams to find which one suits you best (though I know you'll choose this one).
        AH_IT_SAYS_HERE_THAT_YOU_ARE_A                                          = 11748,  -- Ah, it says here that you are a member of the [San d'Oria/Bastok/Windurst] racing team.
