        GOOD_DAY_TO_YOU_SIR_MA_AM_THIS                                          = 12121,  -- Good day to you, sir/ma'am]. This is the entrance to the Chocobo Circuit.
        THE_PORTALS_YOU_SEE_AROUND_YOU_CAN_BE                                   = 12122,  -- The portals you see around you can be used to grant passage to different racetracks.
        HOWEVER_UPON_EXITING_THE_CIRCUIT_YOU_WILL_BE                            = 12123,  -- However, upon exiting the circuit you will be sent back to the precise location you came from, regardless of which exit you use.
        IF_YOU_SHOULD_HAPPEN_TO_GET_LOST_ON                                     = 12124,  -- If you should happen to get lost on the circuit grounds, please consult one of the attendants with red berets. They will be able to help you get around.
