        AND_YES_IT_WOULD_SEEM_YOU_RE_AT                                         = 12940,  -- And yes, it would seem you're at just the right skill level to receive my training. So, what will it be? Which technique would you like to improve?
        TRAIN_IN_WHICH_TECHNIQUE_CANCEL_FEWELL_FEEDING_CURRENT                  = 12941,  -- Train in which technique? Cancel. Fewell feeding. (Current Lv.: #) Furnace thwacking. (Current Lv.: #) Pressure handle. (Current Lv.: #) Safety lever. (Current Lv.: #) Furnace repair. (Current Lv.: #) Fewell recycling. (Current Lv.: #)
        YOU_WISH_TO_IMPROVE_YOUR_TECHNIQUE_IS_THIS                              = 12942,  -- You wish to improve your [/fewell feeding/furnace thwacking/pressure handle operation/safety lever operation/furnace repair/fewell recycling] technique. Is this correct?
        IT_WOULD_SEEM_YOUR_TECHNIQUE_ALREADY_EXCEEDS_MY                         = 12943,  -- It would seem your [/fewell feeding/furnace thwacking/pressure handle operation/safety lever operation/furnace repair/fewell recycling] technique already exceeds my own. There is no more I can teach you.
        TRAIN_IN_THIS_TECHNIQUE_YES_NO                                          = 12944,  -- Train in this technique? Yes. No.
        VERY_WELL_NOW_LISTEN_UP_WATCH_CLOSELY_AND                               = 12945,  -- Very well! Now listen up, watch closely, and try to follow along...
        SEE_YOU_TAKE_THIS_PART_HERE_AND_YES                                     = 12946,  -- ...See, you take this part here, and... Yes, yes...just like that...
        NOW_STEADY_HERE_OR_YOU_LL_BE_PICKING                                    = 12947,  -- ...Now steady here, or you'll be picking exploded furnace shrapnel out of your face for a week! Phew, that was a close one...
        AND_BY_APPLYING_COROLLARY_FIVE_OF_HILDOLF_S                             = 12948,  -- ...And by applying Corollary Five of Hildolf's Third Theory of Inverse Transfocal Equilibrium, we find that...
        CLINK_CLANK_CLUNK_ER_LET_S_TRY_THAT                                     = 12949,  -- <Clink, clank...clunk> ...Er, let's try that once more...
        SUPERB_A_QUICK_LEARNER_I_SEE_IF_ONLY                                    = 12950,  -- ...Superb! A quick learner, I see. If only all my students were as attentive as you!
        YOUR_TECHNIQUE_INCREASES_TO_LEVEL                                       = 12951,  -- Your [/fewell feeding/furnace thwacking/pressure handle operation/safety lever operation/furnace repair/fewell recycling] technique increases to level #!
        RESEARCH_INTO_THE_COMPOSITION_OF_THE_CINDER_PRODUCED                    = 12952,  -- Research into the composition of the cinder produced as a side effect of synergy just might lead to the next breakthrough in our field. Provide us with samples for analysis, and we will gladly reward your contributions.
        TRADE_IN_YOUR_CINDER_CURRENTLY_PZ_NOT_NOW                               = 12953,  -- Trade in your cinder? (Currently: # Pz) Not now. %: # Pz. %: # Pz. %: # Pz. %: # Pz. %: # Pz. %: # Pz. %: # Pz. # gil: # Pz.
        THIS_IS_WHAT_YOU_WANT_CORRECT                                           = 12954,  -- This is what you want, correct?
        MAKE_THE_EXCHANGE_YES_NO                                                = 12955,  -- Make the exchange? Yes. No.
        IT_WOULD_APPEAR_THAT_YOU_LACK_THE_NECESSARY                             = 12956,  -- It would appear that you lack the necessary quantity of cinder for that transaction.
        EXCELLENT_AND_THIS_IS_YOURS_MAY_IT_SERVE                                = 12957,  -- Excellent! And this is yours. May it serve you well!
        YOU_TRANSFERRED_PZ_OF_CINDER_TO_THE_SYNERGY                             = 12958,  -- You transferred # Pz of cinder to the synergy engineer. # Pz [remains/remain] in your possession.
        ASK_ABOUT_WHAT_NOTHING_SYNERGY_FURNACES_SYNERGY_OVERVIEW                = 12959,  -- Ask about what? Nothing. Synergy furnaces. Synergy overview. Synergy procedure. Synergy recipes. Fewell replenishment. Materials for sale. Synergy techniques. Trading cinder.
        THE_SYNERGY_FURNACES_YOU_SEE_AROUND_TOWN_ARE                            = 12960,  -- The synergy furnaces you see around town are provided as a public service by the Bastokan Institute of Synergy Research, to ensure that no synergist is ever far away from the tools of their trade.
        THE_SYNERGIST_MUST_PROVIDE_HIS_OR_HER_OWN                               = 12961,  -- The synergist must provide his or her own %, as well as any materials to be used in the synergy process. Provided those conditions are met, synergy furnaces may be used free of charge.
        NEEDLESS_TO_SAY_ONLY_ONE_PARTY_MAY_OPERATE                              = 12962,  -- Needless to say, only one party may operate any given furnace at once.
        FORTUNATELY_THERE_ARE_MULTIPLE_FURNACES_INSTALLED_THROUGHOUT_TOWN       = 12963,  -- Fortunately, there are multiple furnaces installed throughout town. If the furnace before you is already in use, please seek out an unused one elsewhere, or wait patiently for your turn.
        YOU_MAY_THINK_OF_SYNERGY_AS_AN_EVOLVED                                  = 12964,  -- You may think of synergy as an evolved form of synthesis. It is a discipline full of heretofore unimagined possibilities, but one which demands consummate skill from its practitioners.
        LIKE_SYNTHESIS_SYNERGY_INVOLVES_COMBINING_MATERIALS_ACCORDING_TO        = 12965,  -- Like synthesis, synergy involves combining materials according to a prescribed recipe to yield oft-spectacular results. The rub is that each synergy recipe also dictates a certain elemental balance that must be achieved for the procedure to be successful.
        THIS_BALANCE_IS_ACHIEVED_THROUGH_SKILLFUL_INFUSION_OF                   = 12966,  -- This balance is achieved through skillful infusion of combustible elemental crystals that we synergists call fewell. To begin the synergy process, you'll have to feed the furnace with fewell and get those flames burning!
        AS_A_GENERAL_RULE_THE_MORE_COMPLEX_THE                                  = 12967,  -- As a general rule, the more complex the recipe, the more fewell it will require. Take care to check your stock before you fire up the furnace, lest you find its flames guttering out at a crucial moment.
        WITH_THE_BELLY_OF_THE_FURNACE_ROARING_UP                                = 12968,  -- With the belly of the furnace roaring up a storm, it's time to toss in your materials and start synergizing! Keep a close eye on the balance of elements and deploy fewell as necessary. Approach the prescribed elemental balance, and your item will take form, allowing you to remove it from the furnace.
        THE_CLOSER_YOU_ARE_TO_THE_IDEAL_ELEMENTAL                               = 12969,  -- The closer you are to the ideal elemental balance, the higher the quality of your finished product will be. In synergy, it pays to be a perfectionist!
        BUT_BE_FOREWARNED_THESE_FURNACES_CAN_ONLY_SUSTAIN                       = 12970,  -- But be forewarned: these furnaces can only sustain the elemental maelstrom swirling and storming inside them for so long.
        IF_THE_FURNACE_S_DURABILITY_SHOULD_FAIL_THE                             = 12971,  -- If the furnace's durability should fail, the synergy process will be interrupted, and you will be forced to start anew.
        TAKE_HEART_THOUGH_AS_ANY_MATERIALS_INSIDE_YOUR                          = 12972,  -- Take heart, though, as any materials inside your % will remain intact. You may retrieve them or attempt the synergy process again as you see fit.
        ANY_FEWELL_CONSUMED_IN_THE_FAILED_SYNERGY_ATTEMPT                       = 12973,  -- Any fewell consumed in the failed synergy attempt, on the other hand, will be permanently lost.
        SYNERGISTS_MUST_ALSO_BE_WARY_OF_DEBRIS_BUILDUP                          = 12974,  -- Synergists must also be wary of debris buildup, an unavoidable side effect of the volatile elemental reactions that take place within the synergy furnace.
        SHOULD_TOO_MUCH_DEBRIS_BE_ALLOWED_TO_ACCUMULATE                         = 12975,  -- Should too much debris be allowed to accumulate, the contents of the furnace will become unstable, potentially leading to unpleasant explosions and eruptions. Such accidents pose considerable risk to the synergy attempt in progress, as well as the physical well-being of the synergist, so be sure to exercise due caution!
        YOU_MAY_BE_ASKING_YOURSELF_WHY_HOW_IN                                   = 12976,  -- You may be asking yourself, Why, how in the name of Hildolf am I going to oversee all of these complicated procedures and variables by myself?
        HERE_S_THE_GOOD_NEWS_YOU_DON_T                                          = 12977,  -- Here's the good news: you don't have to! For you see, synergy furnaces are designed for use by multiple operators.
        THE_MORE_COMPLEX_THE_RECIPE_THE_GREATER_LEVEL                           = 12978,  -- The more complex the recipe, the greater level of skill and hands-on manipulation it will demand. At such times, it would be in your best interest to seek out like-minded synergists and take on the challenge together.
        FINALLY_IT_WOULD_BE_REMISS_OF_ME_NOT                                    = 12979,  -- Finally, it would be remiss of me not to make mention of %, the curious substance whose properties are only now--with the emergence of synergy--becoming known to us.
        THOUGH_THERE_IS_MUCH_YET_TO_BE_LEARNED                                  = 12980,  -- Though there is much yet to be learned, our research has revealed that % may be used to bolster your equipment, if attached in a proper manner.
        MIND_YOU_IS_NOT_EASY_TO_COME_BY                                         = 12981,  -- Mind you, % is not easy to come by, and I can offer no clues as to where or how to obtain it. Should you be fortunate enough to come across some in your travels, however, I encourage you to explore its potential.
        SYNERGY_IS_NOT_A_DISCIPLINE_FOR_THE_FAINT                               = 12982,  -- Synergy is not a discipline for the faint of heart or mind, but with dedication and cooperation, there are great rewards to be reaped. May your career as a synergist prove fruitful!
        FIRST_YOU_LL_BE_WANTING_TO_CHECK_YOUR                                   = 12983,  -- First, you'll be wanting to check your fewell supply. You may do so by speaking with a synergy engineer such as myself, or by examining a synergy furnace.
        YOU_LL_BE_NEEDING_AT_LEAST_ONE_UNIT                                     = 12984,  -- You'll be needing at least one unit of fewell for each element dictated by your recipe. Without this, even the most skilled synergist cannot hope to succeed.
        SHOULD_YOUR_FEWELL_SUPPLY_BE_IN_ORDER_IT                                = 12985,  -- Should your fewell supply be in order, it's time to proceed with the synergy. If you are using one of these public synergy furnaces here, you'll need to examine it and lay claim to its use.
        YOU_MAY_THEN_DEPOSIT_YOUR_INGREDIENTS_SHOULD_THEY                       = 12986,  -- You may then deposit your ingredients. Should they correspond to a proper recipe, the synergy furnace will fire up automatically. Note that as a safety precaution, the furnace will not activate if the recipe is beyond your level of synergy skill.
        FROM_HERE_IT_BECOMES_A_RACE_AGAINST_THE                                 = 12987,  -- From here, it becomes a race against the clock! Through skilled operation of the synergy furnace, you must achieve the elemental balance prescribed by the recipe before the furnace's durability fails.
        FORTUNATELY_SYNERGY_FURNACES_ARE_OUTFITTED_WITH_A_WIDE                  = 12988,  -- Fortunately, synergy furnaces are outfitted with a wide array of features designed to aid the synergist in this demanding task. First, you'll want to confirm the current balance of elements within the furnace and compare it to your desired result.
        NEXT_YOU_CAN_BEGIN_TO_FEED_FEWELL_INTO                                  = 12989,  -- Next, you can begin to feed fewell into the furnace to gradually raise the level of elemental concentration. Feeding fewell into the furnace until the required elemental balance is achieved is the most fundamental operation of synergy.
        HOWEVER_HIGH_CONCENTRATIONS_OF_ELEMENTAL_POWER_CAN_LEAD                 = 12990,  -- However, high concentrations of elemental power can lead to volatile and unpredictable reactions. Simply adding fewell haphazardly without making the necessary adjustments is a recipe for only one thing, and that's disaster.
        IF_YOU_SENSE_THAT_THE_FURNACE_IS_ON                                     = 12991,  -- If you sense that the furnace is on the verge of elemental overload, you'll want to employ the safety lever and pressure handle to prevent an unfortunate accident from occurring.
        YOU_LL_ALSO_WANT_TO_MIND_THE_LAWS                                       = 12992,  -- You'll also want to mind the laws of elemental ascendancy and opposition. Increasing the concentration of a particular element will cause its counterpart to decrease.
        THE_FURNACE_CANNOT_SUSTAIN_ITS_POWER_INDEFINITELY_AND                   = 12993,  -- The furnace cannot sustain its power indefinitely, and will gradually lose durability as the synergy process continues. You'll need to perform periodic furnace repair should the furnace near its breaking point.
        IT_IS_ALSO_POSSIBLE_TO_RECYCLE_STREWN_FEWELL                            = 12994,  -- It is also possible to recycle strewn fewell during synergy. While this will not impact the success or failure of the process itself, it will result in a greater amount of salvageable cinder produced as a by-product.
        THIS_CINDER_IS_OF_GREAT_INTEREST_TO_OUR                                 = 12995,  -- This cinder is of great interest to our researchers back at the institute. As such, we have introduced a reward system through which quality samples can be traded in for an assortment of synergy-related wares.
        AS_MARVELOUS_AN_APPARATUS_AS_THE_SYNERGY_FURNACE                        = 12996,  -- As marvelous an apparatus as the synergy furnace may be, keep in mind that the technology is still in its infancy, and highly unstable. There may be times when accidents occur despite the best efforts of the synergist.
        FOR_YOUR_SAFETY_WE_RECOMMEND_STEPPING_AS_FAR                            = 12997,  -- For your safety, we recommend stepping as far away from the furnace as possible at the first sign of danger. Some synergists claim that giving the furnace a good thwack is also effective in preventing such accidents, but this is pure madness, if you ask me!
        YOU_WILL_ALSO_FIND_THAT_THERE_ARE_NUMEROUS                              = 12998,  -- You will also find that there are numerous techniques that can be applied to make the synergy procedure go even more smoothly.
        IN_MANY_CASES_EXPERTISE_AND_KNOWLEDGE_ACQUIRED_THROUGH                  = 12999,  -- In many cases, expertise and knowledge acquired through crafting will serve you in synergy as well. To truly master synergy, one must master crafting as well.
        NOW_LET_US_RETURN_TO_THE_SYNERGY_PROCESS                                = 13000,  -- Now let us return to the synergy process itself. As your elemental balance approaches that prescribed by the recipe, the furnace will signal you, and you may retrieve your finished product.
        IF_THE_FURNACE_IS_STILL_HOLDING_STRONG_AT                               = 13001,  -- If the furnace is still holding strong at this time, you may choose to keep working to achieve an even closer balance. The closer you come to the ideal balance, the higher the quality of your finished product will be.
        INDEED_MANY_SYNERGY_MASTERS_CONSIDER_THESE_WANING_MOMENTS               = 13002,  -- Indeed, many synergy masters consider these waning moments after the signal to be the time to really show off their skills! Why, if they manage to achieve an elemental surge...
        WHAT_S_AN_ELEMENTAL_SURGE_YOU_ASK_WHY                                   = 13003,  -- What's an elemental surge, you ask? Why, it's a miraculous phenomenon that occurs rarely--ever so rarely--upon feeding the furnace fewell.
        THE_ELEMENTS_REACT_JUST_IN_THE_RIGHT_WAY                                = 13004,  -- The elements react just in the right way, creating a miraculous reaction that brings the level of elemental concentration to exactly the desired level. Truly a boon from the Goddess for any synergist, no?
        AND_THAT_IS_THE_SYNERGY_PROCESS_IN_A                                    = 13005,  -- ...And that is the synergy process in a nutshell. There's quite a bit of information to take in, so don't hesitate to return any time for a refresher course.
        MUCH_LIKE_SYNTHESIS_TO_FASHION_ITEMS_THROUGH_SYNERGY                    = 13006,  -- Much like synthesis, to fashion items through synergy, you will need to follow a recipe. We synergy engineers are always unearthing new recipes, and are happy to share with you those suitable for your level of skill.
        UNLIKE_SYNTHESIS_HOWEVER_A_SYNERGY_RECIPE_IS_MORE                       = 13007,  -- Unlike synthesis, however, a synergy recipe is more than just a list of ingredients. There is also a required elemental balance that must be attained to achieve your desired result.
        SIMPLE_RECIPES_INVOLVE_ONLY_SMALL_DOSES_OF_A                            = 13008,  -- Simple recipes involve only small doses of a limited number of elements, but more complex ones require the synergist to skillfully juggle wide ranges of elements in extremely high concentrations.
        THE_INGREDIENTS_YOU_WILL_HAVE_TO_REMEMBER_ON                            = 13009,  -- The ingredients, you will have to remember on your own. The required elemental balance, however, may be reviewed at any time during the synergy process by observing the readings on the synergy furnace.
        IN_PARTICULAR_RECIPES_THROUGH_WHICH_THE_CURIOUS_SUBSTANCE               = 13010,  -- In particular, recipes through which the curious substance known as % can be attached to equipment are creating quite a buzz among synergistically inclined adventurers these days.
        CANNOT_BE_ATTACHED_DIRECTLY_FIRST_EQUIPMENT_MUST_BE                     = 13011,  -- % cannot be attached directly. First, equipment must be prepared by etching an aperture into which an elementally compatible piece of % can then be embedded.
        THE_TYPE_OF_APERTURE_THAT_MAY_BE_ETCHED                                 = 13012,  -- The type of aperture that may be etched will depend on the piece of equipment. There are also pieces of equipment that, alas, may not be modified at all.
        IF_YOU_ARE_CURIOUS_WHAT_MANNER_OF_APERTURE                              = 13013,  -- If you are curious what manner of aperture may be etched into a particular piece of equipment, you need only trade it to me or one of my colleagues.
        AS_A_GENERAL_RULE_THE_HIGHER_THE_LEVEL                                  = 13014,  -- As a general rule, the higher the level of the item in question, the more difficult the synergy process for creating an aperture will be.
        YOU_WILL_FIND_THAT_CERTAIN_PIECES_OF_EQUIPMENT                          = 13015,  -- You will find that certain pieces of equipment may be etched with multiple apertures. It is, however, only possible to create one aperture at a time.
        ETCHING_REQUIRES_THE_USE_OF_A_CORROSIVE_SUBSTANCE                       = 13016,  -- Etching requires the use of a corrosive substance we call mordant. Deposit mordant into a synergy furnace along with your equipment, and the process will begin.
        MY_COLLEAGUES_AND_I_HAVE_A_STOCK_OF                                     = 13017,  -- My colleagues and I have a stock of mordant available for sale. The best way to learn is to practice, so if you're curious, we encourage you to purchase some and begin experimenting!
        THE_DIFFICULTY_OF_THE_SYNERGY_PROCESS_WHEN_EMBEDDING                    = 13018,  -- The difficulty of the synergy process when embedding evolith is decided by a number of factors.
        SUCH_FACTORS_INCLUDE_THE_VARIETY_OF_APERTURE_AND                        = 13019,  -- Such factors include the variety of aperture and evolith, as well as the quantity of evolith you seek to attach. Embedding the first piece is not too difficult a task, but the second and third pieces will not go in so easily.
        TO_BEGIN_THE_EMBEDDING_PROCESS_DEPOSIT_YOUR_EVOLITH                     = 13020,  -- To begin the embedding process, deposit your evolith into the synergy furnace along with a piece of equipment with a compatible aperture.
        WHEN_ETCHING_OR_EMBEDDING_THE_REQUIRED_ELEMENTAL_BALANCE                = 13021,  -- When etching or embedding, the required elemental balance may be confirmed at any time during the synergy process, so let this be your guide.
        SHOULD_YOU_EVER_WISH_TO_REMOVE_ANY_APERTURES                            = 13022,  -- Should you ever wish to remove any apertures and embedded evolith from a piece of equipment entirely, you may do so with an ingredient we call revertant.
        TOSS_THE_REVERTANT_IN_A_SYNERGY_FURNACE_ALONG                           = 13023,  -- Toss the revertant in a synergy furnace along with your equipment, and its potent powers will restore your item to a pure and pristine state! Be warned, however, that embedded evolith will be lost forever in the process.
        AS_YOU_ARE_NO_DOUBT_ALREADY_AWARE_SYNERGY                               = 13024,  -- As you are no doubt already aware, synergy makes use of a highly combustible form of elemental crystals that we call fewell. The more complex the recipe, the greater the quantity of fewell required.
        VETERAN_SYNERGISTS_KNOW_WELL_THE_HASSLE_OF_HAVING                       = 13025,  -- Veteran synergists know well the hassle of having to constantly monitor their fewell supply and procure crystals to replenish depleted stock.
        TO_FREE_YOU_OF_SUCH_TRIFLING_BURDENS_AND                                = 13026,  -- To free you of such trifling burdens and allow you to focus your mind entirely on your art, we synergy engineers are offering a convenient fewell replenishment service!
        FOR_A_NOMINAL_FEE_CALCULATED_BASED_UPON_THE                             = 13027,  -- For a nominal fee calculated based upon the current state of your fewell reserves, we will instantly refill you to full capacity.
        THAT_S_RIGHT_ALL_ELEMENTS_IN_ONE_SIMPLE                                 = 13028,  -- That's right--all elements in one simple transaction, directly to your %! What could be easier?
        LOOKING_TO_FIRE_UP_YOUR_FURNACE_AND_ENTER                               = 13029,  -- Looking to fire up your furnace and enter the world of %? If so, you've come to the right place!
        WE_RE_PROUD_TO_OFFER_A_SUPPLY_OF                                        = 13030,  -- We're proud to offer a supply of the corrosive agent known as mordant for sale. With this, synergy newcomers can hone their skills and outfit their equipment with evolith-capable apertures in the process.
        MIND_YOU_OUR_STOCK_IS_LIMITED_TO_ONLY                                   = 13031,  -- Mind you, our stock is limited to only the most diluted, readily produced form of the stuff. You'll find that it only has the strength to etch items of relatively low level.
        ETCHING_HIGH_POWERED_EQUIPMENT_REQUIRES_THE_USE_OF                      = 13032,  -- Etching high-powered equipment requires the use of more concentrated and potent forms of mordant. As quantities are limited, we can offer these only in exchange for cinder.
        AH_SYNERGY_TECHNIQUES_THOSE_HANDY_TRICKS_OF_THE                         = 13033,  -- Ah, synergy techniques! Those handy tricks of the trade that can mean the difference between a shiny new item and a major furnace meltdown.
        MY_COLLEAGUES_AND_I_ARE_ALWAYS_EAGER_TO                                 = 13034,  -- My colleagues and I are always eager to train fellow synergists in a wide range of techniques. We can't do it all, though--you'll need to hone your synergy skill in order to benefit from our instruction.
        BEAR_IN_MIND_THAT_CERTAIN_TECHNIQUES_CAN_ONLY                           = 13035,  -- Bear in mind that certain techniques can only be imparted to students possessing specialized crafting knowledge. For example, only skilled smiths will be able to comprehend the method for more efficient fewell feeding.
        ACCOMPLISHED_GOLDSMITHS_WILL_BE_ABLE_TO_OBSERVE_THE                     = 13036,  -- Accomplished goldsmiths will be able to observe the inner workings of the furnace and stave off potential accidents. You will find that all crafting skills--even those you may not expect--may be applied in some way to support the synergy process.
        WORD_HAS_IT_THAT_THERE_ARE_ALSO_PIECES                                  = 13037,  -- Word has it that there are also pieces of equipment that can impart hidden synergy techniques to the wearer. These, too, are said to be only accessible to skilled crafters.
        THE_MORAL_OF_THE_STORY_IS_THIS_WHILE                                    = 13038,  -- The moral of the story is this: while synergy skill is important, neglect not your other crafting skills. To become a true synergy master, finding the proper balance is key.
        SYNERGY_REMAINS_A_YOUNG_DISCIPLINE_AND_RESEARCHERS_BACK                 = 13039,  -- Synergy remains a young discipline, and researchers back at the institute are burning the midnight fewell in the hopes of uncovering the next breakthrough in our field.
        RESEARCH_OF_LATE_IS_CENTERED_AROUND_THE_CINDER                          = 13040,  -- Research of late is centered around the cinder that is left behind as a by-product of each synergy operation. Their composition, it would seem, has much to teach us of the true nature of the complex elemental reactions that go on within the bellies of these furnaces.
        WE_VE_EVEN_INSTITUTED_A_REWARD_PROGRAM_FOR                              = 13041,  -- We've even instituted a reward program for adventurers willing to contribute prime samples in the name of science.
        IT_WOULD_BE_NO_EXAGGERATION_TO_SAY_THAT                                 = 13042,  -- It would be no exaggeration to say that, to us, cinder is worth more than its weight in gold! Bring it to me or my colleagues--preferably in large quantities--and you're sure to be pleased at what we can offer you in return.
        WONDERING_IF_YOUR_CAN_BE_OUTFITTED_WITH_EVOLITH                         = 13043,  -- Wondering if your % can be outfitted with evolith, are you? Well, you've come to the right place!
        A_QUICK_LOOK_AT_ITS_COMPOSITION_SHOULD_TELL                             = 13044,  -- A quick look at its composition should tell us all we need to know. Let's see here...
        CONGRATULATIONS_YOUR_CAN_INDEED_HOLD_EVOLITH_APERTURE_A                 = 13045,  -- Congratulations! Your % can indeed hold [an/another] evolith aperture. A %-shaped aperture, to be exact...
        SUITABLE_FOR_EVOLITH_OF_THE_FOLLOWING_SIZE_AND                          = 13046,  -- ...Suitable for evolith of the following size and elemental affinity: Maximum size: # / [/oo /o!/o"/o#/o$/o%/o&].
        SUITABLE_FOR_EVOLITH_OF_THE_FOLLOWING_SIZES_AND                         = 13047,  -- ...Suitable for evolith of the following sizes and elemental affinities: Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&].
        SUITABLE_FOR_EVOLITH_OF_THE_FOLLOWING_SIZES_AND_2                       = 13048,  -- ...Suitable for evolith of the following sizes and elemental affinities: Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&].
        SUITABLE_FOR_EVOLITH_OF_THE_FOLLOWING_SIZES_AND_3                       = 13049,  -- ...Suitable for evolith of the following sizes and elemental affinities: Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&].
        THAT_IS_ALL_SHOULD_YOU_WISH_TO_HAVE                                     = 13050,  -- That is all. Should you wish to have any other pieces of equipment analyzed, you know where to find us.
        HMM_I_M_AFRAID_YOUR_CANNOT_HOUSE_ANY                                    = 13051,  -- Hmm... I'm afraid your % cannot house any more apertures.
        ALAS_IT_S_A_SHAME_BUT_IT_APPEARS                                        = 13052,  -- ...Alas. It's a shame, but it appears your % cannot be etched.
        HMM_WHAT_S_THIS_IT_WOULD_SEEM_THAT                                      = 13053,  -- Hmm, what's this? It would seem that your % cannot be etched at this time.
        DO_YOU_LOVE_SYNERGIZING_AS_MUCH_AS_I                                    = 13054,  -- Do you love synergizing as much as I love synergizing!? 'Cause if you do, you're gonna loooooove the recipes I have for you!
        VIEW_RECIPES_FOR_WHICH_SKILL_LEVEL_ACTUALLY_NEVER                       = 13055,  -- View recipes for which skill level? Actually, never mind. Amateur. Recruit. Initiate. Novice. Apprentice. Journeyman. Craftsman. Artisan. Adept. Veteran.
