        WAIT_NO_DON_T_TELL_ME_YOU_STRIKE                                        = 13060,  -- Wait! No, don't tell me. You strike me as a man/woman] who's looking to learn a thing or two about synergy.
        LEARN_ABOUT_SYNERGY_NOT_TODAY_TEACH_ME_JUST                             = 13061,  -- Learn about synergy? Not today. Teach me! Just give me %.
        A_LIFE_WITHOUT_INTELLECTUAL_CURIOSITY_IS_A_LIFE                         = 13062,  -- A life without intellectual curiosity is a life hardly worth living. Should your eyes one day open to this truth, you are free to return.
        I_THOUGHT_YOU_D_NEVER_ASK_SYNERGY_IS                                    = 13063,  -- I thought you'd never ask! Synergy is both an art and a science: an evolution--nay, a revolution--in synthesis.
