        WHAT_WE_CALL_SERVES_TO_DISPENSE_FEWELL_CRYSTALS                         = 13065,  -- What we call % serves to dispense fewell crystals--the lifeblood of the synergy process--whilst also protecting its contents from the volatile reactions that occur within the bowels of the furnace.
        SYNERGY_FURNACES_HAVE_BEEN_INSTALLED_THROUGHOUT_THE_CITY                = 13066,  -- Synergy furnaces have been installed throughout the city for the use of all synergists. The crucible is sufficiently compact and lightweight that you can carry it with you.
        INITIATING_THE_SYNERGY_PROCESS_IS_AS_SIMPLE_AS                          = 13067,  -- Initiating the synergy process is as simple as inserting your % into a furnace and commencing the infusion of elemental fewell.
        NEEDLESS_TO_SAY_WHAT_WILL_HAPPEN_FROM_THERE                             = 13068,  -- Needless to say, what will happen from there is not quite so simple.
        SUCCESSFUL_SYNERGY_IS_CONTINGENT_UPON_MAINTAINING_ELEMENTAL_EQUILIBRIUM = 13069,  -- Successful synergy is contingent upon maintaining elemental equilibrium. The prescribed ratio, of course, will vary depending on the artifact you are attempting to create.
        YOU_CAN_INCREASE_THE_RATIO_OF_A_PARTICULAR                              = 13070,  -- You can increase the ratio of a particular element by burning the corresponding variety of fewell.
        BUT_HEREIN_LIES_THE_RUB_SYNERGY_IS_A                                    = 13071,  -- But herein lies the rub: synergy is a still young science, and the technology we employ remains, shall we say...unstable.
        A_BIT_TOO_MUCH_FEWELL_HERE_A_WRONG                                      = 13072,  -- A bit too much fewell here, a wrong lever pulled there, and the percolating pot will explode, spitting scalding elemental guck every which way to Firesday.
        THAT_S_WHY_SMART_SYNERGISTS_SYNERGIZE_IN_NUMBERS                        = 13073,  -- That's why smart synergists synergize in numbers. Too many culinarians might spoil the broth, but when it comes to synergy, it's the more the merrier!
        AN_ASPIRING_SYNERGIST_I_SEE_IF_YOU_RE                                   = 13074,  -- An aspiring synergist, I see! If you're looking for %, you've certainly come to the right place.
