        WHAT_DO_YOU_WANT_TO_LEARN_ABOUT_WHAT                                    = 14076,  -- What do you want to learn about? What is the Assist Channel? How can I post a message? What are the requirements? Where can I access it? Tell me about mentor messages. Where can I find mentors? What are Thumbs Up and Warnings? What happens if I am muted? When do my posting rights expire? Nothing for now.
        THE_ASSIST_CHANNEL_IS_A_SPECIAL_CHAT_CHANNEL                            = 14077,  -- The Assist Channel is a special chat channel that allows adventurers to ask questions and receive advice from veteran players known as mentors.
        PRESS_THE_SPACE_BAR_TO_BRING_UP_THE                                     = 14078,  -- Press the space bar to bring up the text window at the bottom of the screen and type /assistj (your message) or /assiste (your message) to post your message.
        YOU_CAN_ALSO_USE_AJ_FOR_ASSISTJ_AND                                     = 14079,  -- You can also use /aj for /assistj, and /ae for /assiste.
        ADDITIONALLY_PRESSING_CTRL_Q_WILL_DISPLAY_ASSISTJ_OR                    = 14080,  -- Additionally, pressing CTRL+Q will display /assistj or /assiste in the text window for you.
        YOU_CAN_CHANGE_THE_CTRL_Q_SHORTCUT_COMMAND                              = 14081,  -- You can change the CTRL+Q shortcut command...
        BY_GOING_TO_MAIN_MENU_CONFIG_MISC_2                                     = 14082,  -- ...by going to Main Menu > Config > Misc. 2 > Key Assignment > Commands > Chat: /AssistE or /AssistJ.
        IT_IS_RECOMMENDED_THAT_YOU_USE_ASSISTJ_AJ                               = 14083,  -- It is recommended that you use /assistj (/aj) when posting in Japanese, and /assiste (/ae) when posting in English.
        YOU_MUST_MEET_ONE_OF_THE_FOLLOWING_CONDITIONS                           = 14084,  -- You must meet one of the following conditions in order to post to the Assist Channel.
        ID_1_YOU_ARE_A_NEW_PLAYER_YOU_MAY                                       = 14085,  -- 1. You are a new player You may post messages from the moment you first set foot in Vana'diel.
        ID_2_YOU_ARE_A_RETURNEE_AS_A_RETURNING                                  = 14086,  -- 2. You are a returnee As a returning player, you may post messages upon logging in with a character that has not logged in for at least 48 days.
        ID_3_YOU_ARE_A_MENTOR_YOU_MAY_POST                                      = 14087,  -- 3. You are a mentor You may post messages as long as you remain a mentor to other players.
        NEW_PLAYERS_AND_RETURNEES_MAY_POST_MESSAGES_UNTIL                       = 14088,  -- New players and returnees may post messages until they have been logged in for a total of 48 hours since first receiving their posting rights.
        IF_YOU_WISH_TO_CHECK_HOW_LONG_YOU                                       = 14089,  -- If you wish to check how long you can continue to post for, speak to an and choose "When do my posting rights expire?" to see how much time you have left.
