        YOU_CANNOT_POST_OR_READ_MESSAGES_OUTSIDE_OF                             = 14095,  -- You cannot post or read messages outside of the areas listed above.
        EVEN_IN_AREAS_WHERE_MESSAGES_ARE_ALLOWED_YOU                            = 14096,  -- Even in areas where messages are allowed, you cannot post consecutive messages. Please wait a while after posting a message.
        MENTOR_MESSAGES_ARE_ACCOMPANIED_BY_A_FLAG_O                             = 14097,  -- Mentor messages are accompanied by a flag (o/) marker. This marker indicates the mentor's reliability (Mentor Class) and experience as an adventurer (Mastery Rank).
        AS_A_MENTOR_S_MENTOR_CLASS_INCREASES_THE                                = 14098,  -- As a mentor's Mentor Class increases, the color and shape of the marker will change: o/ > o9 > oC
        A_OC_MARKER_IS_A_SIGN_THAT_THE                                          = 14099,  -- A oC marker is a sign that the mentor has earned the highest levels of trust from other adventurers.
        THE_NUMBER_AFFIXED_TO_THE_MARKER_IS_THE                                 = 14100,  -- The number affixed to the marker is the mentor's Mastery Rank, and indicates how experienced the mentor is as an adventurer.
        THE_HIGHER_THE_NUMBER_THE_MORE_EXPERIENCED_THE                          = 14101,  -- The higher the number, the more experienced the mentor is.
        YOU_CAN_CHECK_YOUR_OWN_MASTERY_RANK_EVEN                                = 14102,  -- You can check your own Mastery Rank even if you do not serve as a mentor, so feel free to take a look every now and then if you are curious.
        YOU_CAN_CHECK_YOUR_MASTERY_RANK_BY_GOING                                = 14103,  -- You can check your Mastery Rank by going to Main Menu > Status > Profile.
        IF_YOU_WISH_TO_SPEAK_DIRECTLY_TO_A                                      = 14104,  -- If you wish to speak directly to a mentor, you can search for mentors by going to Main Menu > Help Desk > Mentor Search.
